// ROUTER INTELIGENTE - Detecta confirmaciones y consulta memoria
const respuestaAgent = $json;
const chatId = respuestaAgent.chat_id;

// =============================
// 0) RESPUESTA REAL DEL NODO ANTERIOR (FIX)
// =============================
const Procesar_Respuesta = 'Procesar Respuesta';

const safeFirstJson = (nodeName) => {
  try { return $items(nodeName, 0)?.[0]?.json ?? null; } catch { return null; }
};

const prevNode = safeFirstJson(Procesar_Respuesta) || {};
const respuestaRealAnterior =
  (typeof respuestaAgent.respuesta_usuario === 'string' && respuestaAgent.respuesta_usuario.trim())
    ? respuestaAgent.respuesta_usuario.trim()
    : (typeof prevNode.respuesta_usuario === 'string' && prevNode.respuesta_usuario.trim())
      ? prevNode.respuesta_usuario.trim()
      : '';

// =============================
// MEMORIA desde PostgreSQL
// =============================
const datosConMemoria = $('Preparar Datos AI Agent').first().json;

const parseJSONSafe = (v) => {
  try { return typeof v === 'string' ? JSON.parse(v) : (v || {}); }
  catch { return {}; }
};

let memoria = {
  esperando_confirmacion: datosConMemoria.esperando_confirmacion,
  datos_pendientes_raw: datosConMemoria.datos_pendientes,
  datos_pendientes: parseJSONSafe(datosConMemoria.datos_pendientes),
  ultimo_mensaje_bot: datosConMemoria.ultimo_mensaje_bot || '',
};

console.log('🎯 === ROUTER INTELIGENTE ===');
console.log('📥 Acción recibida:', respuestaAgent.accion);
console.log('💬 Mensaje usuario:', respuestaAgent.mensaje_usuario || respuestaAgent.mensaje_original);
console.log('🧠 Memoria PostgreSQL:', JSON.stringify(memoria, null, 2));
console.log('✅ Respuesta real anterior:', respuestaRealAnterior);

// =============================
// Lista blanca de acciones permitidas
// =============================
const ACCIONES_VALIDAS = new Set([
  'registrar_parte_y_stock',
  'registrar_horas',
  'registrar_fichaje',
  'registrar_gasto',
  'consultar_actividad_usuario',
  'consultar_horas_proyecto',
  'consultar_horas_tarea',
  'consultar_estado_proyecto',
  'firmar_lopd',
  'uso_liberar_coche',
  'uso_liberar_maquina',
  'envio_masivos',
  'mensaje_bienvenida',
  'fallback',
  // Acciones internas ya usadas en el flujo
  'registrar_tarea',
  'conversar',
  'confirmacion_asociar_imagen',
  'preparar_confirmacion_imagen_tarea_elegida',
  'elegir_tarea_imagen_previa',
  'registrar_compra_inventario',
  'consultar_ventas',
  'consultar_facturas',
]);

// =============================
// DETECTAR CONFIRMACIONES INTELIGENTES
// =============================
let accionFinal = respuestaAgent.accion;

let datosFinales = {
  ...respuestaAgent,
  ...(respuestaRealAnterior ? { respuesta_usuario: respuestaRealAnterior } : {}),
};

// Helpers (SOLO UNA VEZ)
const norm = (s) =>
  String(s || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim();

const msgRaw = (
  respuestaAgent.mensaje_original ||
  respuestaAgent.mensaje_usuario ||
  respuestaAgent.text ||
  respuestaAgent.mensaje ||
  ''
).trim();

const msg = norm(msgRaw);

const isYes = ['si', 'sí', 'vale', 'ok', 'perfecto', 'adelante', 'confirmo', 'confirmar', 'hazlo', 'de acuerdo']
  .some(w => msg.includes(norm(w)));

const isNo  = ['no', 'cancelar', 'cancela', 'anula', 'parar', 'nada']
  .some(w => msg.includes(norm(w)));

const esConfirmacion = isYes;
const esNegacion = isNo;

// ✅ CANCELACIÓN DURA (siempre)
const cancelHardPhrases = [
  'cancelar',
  'cancela',
  'cancela la tarea',
  'cancelar tarea',
  'cancela la operacion',
  'cancelar operacion',
  'no quiero seguir',
  'resetea',
  'reset',
  'reinicia',
  'borra memoria',
  'borrar memoria',
  'olvida'
];

const esCancelacionDura = cancelHardPhrases.some(p => msg.includes(norm(p)));

if (esCancelacionDura) {
  // 🔥 limpia memoria legacy global
  if (chatId) {
    const contextoKey = `memoria_${chatId}`;
    try { delete global[contextoKey]; } catch {}
  }

  return {
    ...respuestaAgent,
    accion: 'mensaje_bienvenida',
    respuesta_usuario: 'Soy tu asistente de Odoo. Puedo: 1) registrar partes/horas y fichajes, 2) gestionar proyectos y tareas, 3) registrar gastos y consultar ventas/compras, 4) consultar estado de proyectos y actividad. ¿Qué necesitas ahora?',
    borrar_memoria: true,

    // ✅ para que tu UPDATE/guardado en Postgres lo deje a NULL/vacío
    limpiar_confirmacion: true,
    esperando_confirmacion: null,
    ultimo_mensaje_bot: null,
    datos_pendientes: null,
  };
}

// ===============================
// 1) PRIORIDAD: Confirmaciones FSM
// ===============================
if (memoria.esperando_confirmacion === 'confirmar_tarea_unica') {

  if (esNegacion) {
    accionFinal = 'conversar';
    datosFinales = {
      ...datosFinales,
      accion: 'conversar',
      respuesta_usuario: '✅ Vale, no registro el parte.',
      borrar_memoria: true,
    };
  }
  else if (esConfirmacion) {
    const pendientes = memoria.datos_pendientes || {};
    const dp = pendientes.datos_parte || {};

    accionFinal = 'registrar_tarea';
    datosFinales = {
      ...datosFinales,
      accion: 'registrar_tarea',
      tarea: pendientes.tarea_nombre,
      tarea_id: pendientes.tarea_id,
      proyecto_id: pendientes.proyecto_id,
      proyecto_nombre: pendientes.proyecto_nombre,

      // ✅ travel se conserva (prioridad: datos_parte -> agent -> 0)
      travel_distance_km: dp.travel_distance_km ?? respuestaAgent.travel_distance_km ?? 0,
      travel_time_hours: dp.travel_time_hours ?? respuestaAgent.travel_time_hours ?? 0,

      // ✅ SIEMPRE pasar datos_parte completo (dp)
      datos_parte: dp,
      origen_confirmacion: 'tarea_unica',
    };
  }
  else {
    accionFinal = 'conversar';
    datosFinales = {
      ...datosFinales,
      accion: 'conversar',
      respuesta_usuario: 'Respóndeme "sí" para registrar el parte o "no" para cancelar.',
    };
  }
}

else if (memoria.esperando_confirmacion === 'confirmar_tarea_unica_imagen_previa') {
  const pendientes = memoria.datos_pendientes || {};
  const dp = pendientes.datos_parte || {};

  if (esNegacion) {
    accionFinal = 'conversar';
    datosFinales = {
      ...datosFinales,
      accion: 'conversar',
      respuesta_usuario: 'OK, no asocio la imagen.',
      borrar_memoria: true,
      limpiar_confirmacion: true,
      esperando_confirmacion: null,
      datos_pendientes: null,
    };
  }
  else if (esConfirmacion) {
    accionFinal = 'confirmacion_asociar_imagen';
    datosFinales = {
      ...datosFinales,
      accion: 'confirmacion_asociar_imagen',
      tarea_id: pendientes.tarea_id,
      tarea: pendientes.tarea_nombre,
      tarea_nombre: pendientes.tarea_nombre,
      proyecto_id: pendientes.proyecto_id,
      proyecto_nombre: pendientes.proyecto_nombre,
      datos_parte: dp,
      origen_confirmacion: 'confirmar_tarea_unica_imagen_previa',
    };
  }
  else {
    accionFinal = 'conversar';
    datosFinales = {
      ...datosFinales,
      accion: 'conversar',
      respuesta_usuario: 'Resp?ndeme "s?" para asociar la imagen o "no" para cancelar.',
    };
  }
}


else if (memoria.esperando_confirmacion === 'elegir_tarea_multiple') {
  const pendientes = memoria.datos_pendientes || {};
  const dp = pendientes.datos_parte || {};
  const opciones = pendientes.tareas_opciones || [];

  if (esNegacion) {
    accionFinal = 'conversar';
    datosFinales = {
      ...datosFinales,
      accion: 'conversar',
      respuesta_usuario: '✅ Vale, cancelado. No registro nada.',
      borrar_memoria: true,
    };
  }
  else {
    const n = parseInt(msgRaw, 10);

    if (Number.isFinite(n) && n >= 1 && n <= opciones.length) {
      const t = opciones[n - 1];

      accionFinal = 'registrar_tarea';
      datosFinales = {
        ...datosFinales,
        accion: 'registrar_tarea',
        tarea: t.nombre_completo,
        tarea_id: t.id,
        proyecto_id: t.proyecto_id,
        proyecto_nombre: t.proyecto_nombre,

        // ✅ travel se conserva
        travel_distance_km: dp.travel_distance_km ?? respuestaAgent.travel_distance_km ?? 0,
        travel_time_hours: dp.travel_time_hours ?? respuestaAgent.travel_time_hours ?? 0,

        datos_parte: dp,
        origen_confirmacion: 'tarea_multiple_numero',
      };
    }
    else {
      const matches = opciones.filter(o => {
        const nom = norm(o.nombre_completo);
        return nom === msg || nom.includes(msg) || msg.includes(nom);
      });

      if (matches.length === 1) {
        const t = matches[0];

        accionFinal = 'registrar_tarea';
        datosFinales = {
          ...datosFinales,
          accion: 'registrar_tarea',
          tarea: t.nombre_completo,
          tarea_id: t.id,
          proyecto_id: t.proyecto_id,
          proyecto_nombre: t.proyecto_nombre,

          // ✅ travel se conserva
          travel_distance_km: dp.travel_distance_km ?? respuestaAgent.travel_distance_km ?? 0,
          travel_time_hours: dp.travel_time_hours ?? respuestaAgent.travel_time_hours ?? 0,

          datos_parte: dp,
          origen_confirmacion: 'tarea_multiple_nombre',
        };
      }
      else if (matches.length > 1) {
        accionFinal = 'conversar';
        datosFinales = {
          ...datosFinales,
          accion: 'conversar',
          respuesta_usuario: 'Hay varias tareas parecidas. Responde con el número (1,2,3...).',
        };
      }
      else {
        accionFinal = 'conversar';
        datosFinales = {
          ...datosFinales,
          accion: 'conversar',
          respuesta_usuario: `No identifico esa tarea. Responde con el número (1 a ${opciones.length}).`,
        };
      }
    }
  }
}
else if (memoria.esperando_confirmacion === 'elegir_tarea_multiple_imagen_previa') {
  const pendientes = memoria.datos_pendientes || {};
  const dp = pendientes.datos_parte || {};
  const opciones = pendientes.tareas_opciones || [];

  if (esNegacion) {
    accionFinal = 'conversar';
    datosFinales = {
      ...datosFinales,
      accion: 'conversar',
      respuesta_usuario: 'OK, cancelado. No asocio la imagen.',
      borrar_memoria: true,
      limpiar_confirmacion: true,
      esperando_confirmacion: null,
      datos_pendientes: null,
    };
  } else {
    // Texto del USUARIO (no respuesta_usuario del AI: suele ser 'procesando...' y oculta el '2')
    const textoSeleccion = String(
      datosConMemoria.mensaje_usuario_original ||
      datosConMemoria.mensaje_usuario ||
      respuestaAgent.mensaje_original ||
      msgRaw ||
      ''
    ).trim();
    // Mensaje solo numero = indice de lista; primer \d+ en texto largo podria ser S00008, etc.
    let n = NaN;
    if (/^\d{1,3}$/.test(textoSeleccion)) {
      n = parseInt(textoSeleccion, 10);
    } else {
      const digitMatch = textoSeleccion.match(/\d+/);
      n = digitMatch ? parseInt(digitMatch[0], 10) : NaN;
    }
    const msgSel = norm(textoSeleccion);

    const aplicarTareaElegida = (t) => {
      accionFinal = 'confirmacion_asociar_imagen';
      datosFinales = {
        ...datosFinales,
        accion: 'confirmacion_asociar_imagen',
        asociar_imagen_implicito: true,
        tarea_id: t.id,
        tarea_nombre: t.nombre_completo,
        proyecto_id: t.proyecto_id,
        proyecto_nombre: t.proyecto_nombre,
        datos_parte: dp,
      };
    };

    if (Number.isFinite(n) && n >= 1 && n <= opciones.length) {
      aplicarTareaElegida(opciones[n - 1]);
    } else {
      const matches = opciones.filter((o) => {
        const nom = norm(o.nombre_completo);
        return nom === msgSel || (nom.length >= 3 && (nom.includes(msgSel) || msgSel.includes(nom)));
      });

      if (matches.length === 1) {
        aplicarTareaElegida(matches[0]);
      } else if (matches.length > 1) {
        accionFinal = 'conversar';
        datosFinales = {
          ...datosFinales,
          accion: 'conversar',
          respuesta_usuario: 'Hay varias tareas parecidas. Responde solo con el número (1, 2, 3...).',
        };
      } else {
        accionFinal = 'conversar';
        datosFinales = {
          ...datosFinales,
          accion: 'conversar',
          respuesta_usuario:
            opciones.length > 0
              ? `No identifico esa tarea. Responde con el número del 1 al ${opciones.length}.`
              : 'No tengo la lista de tareas en memoria. Vuelve a enviar la imagen para reintentarlo.',
        };
      }
    }
  }
}

else if (memoria.esperando_confirmacion === 'elegir_tarea_lopd') {
  const pendientes = memoria.datos_pendientes || {};
  const opciones = pendientes.tareas_opciones || [];

  if (esNegacion) {
    accionFinal = 'conversar';
    datosFinales = {
      ...datosFinales,
      accion: 'conversar',
      respuesta_usuario: '✅ Vale, cancelado.',
      borrar_memoria: true,
      limpiar_confirmacion: true,
      esperando_confirmacion: null,
      datos_pendientes: null,
    };
  }
  else {
    const n = parseInt(msgRaw, 10);
    if (Number.isFinite(n) && n >= 1 && n <= opciones.length) {
      const t = opciones[n - 1];
      const baseUrl = 'https://mchecagoshawk-webinar.odoo.com';
      const urlLopd = `${baseUrl}/firma-lopd/${t.id}`;

      accionFinal = 'conversar';
      datosFinales = {
        ...datosFinales,
        accion: 'conversar',
        respuesta_usuario: `✅ Aquí tienes el enlace para firmar la LOPD:\n\n${urlLopd}\n\nAbre el enlace en tu navegador (debes estar conectado a Odoo).`,
        borrar_memoria: true,
        limpiar_confirmacion: true,
        esperando_confirmacion: null,
        datos_pendientes: null,
      };
    }
    else {
      accionFinal = 'conversar';
      datosFinales = {
        ...datosFinales,
        accion: 'conversar',
        respuesta_usuario: `Responde con el número (1 a ${opciones.length}) para obtener el enlace de firma LOPD.`,
      };
    }
  }
}

// ===============================
// 1b) Confirmaciones USO/LIBERAR COCHE
// ===============================
else if (memoria.esperando_confirmacion === 'confirmar_usar_coche_cambio') {
  const pendientes = memoria.datos_pendientes || {};
  if (esNegacion) {
    accionFinal = 'conversar';
    datosFinales = { ...datosFinales, accion: 'conversar', respuesta_usuario: '✅ Vale, no cambio el coche.', borrar_memoria: true };
  } else if (esConfirmacion) {
    accionFinal = 'uso_liberar_coche';
    datosFinales = { ...datosFinales, accion: 'uso_liberar_coche', tipo_accion: 'usar', coche_id: pendientes.vehicle_id, coche_nombre: pendientes.vehicle_name, partner_id: pendientes.partner_id, confirmar_cambio: true };
  } else {
    accionFinal = 'conversar';
    datosFinales = { ...datosFinales, accion: 'conversar', respuesta_usuario: '¿Quieres que asigne ese coche a tu usuario? Responde sí o no.' };
  }
}
else if (memoria.esperando_confirmacion === 'elegir_coche_usar') {
  const pendientes = memoria.datos_pendientes || {};
  const opciones = pendientes.coches_libres || [];
  if (esNegacion) {
    accionFinal = 'conversar';
    datosFinales = { ...datosFinales, accion: 'conversar', respuesta_usuario: '✅ Vale, no asigno ningún coche.', borrar_memoria: true };
  } else {
    const n = parseInt(msgRaw, 10);
    if (Number.isFinite(n) && n >= 1 && n <= opciones.length) {
      const c = opciones[n - 1];
      const fmt = v => `${v.name || 'Sin nombre'} (${v.license_plate || 'sin matrícula'})`;
      accionFinal = 'uso_liberar_coche';
      datosFinales = { ...datosFinales, accion: 'uso_liberar_coche', tipo_accion: 'usar', vehicle_id: c.id, coche_id: c.id, partner_id: pendientes.partner_id, coche_nombre: fmt(c) };
    } else {
      const match = opciones.find(o => norm(o.name||'').includes(msg) || norm(o.license_plate||'').includes(msg) || msg.includes(norm(o.name||'')) || msg.includes(norm(o.license_plate||'')));
      if (match) {
        const fmt = v => `${v.name || 'Sin nombre'} (${v.license_plate || 'sin matrícula'})`;
        accionFinal = 'uso_liberar_coche';
        datosFinales = { ...datosFinales, accion: 'uso_liberar_coche', tipo_accion: 'usar', vehicle_id: match.id, coche_id: match.id, partner_id: pendientes.partner_id, coche_nombre: fmt(match) };
      } else if (msg.includes('usar') && msg.includes('coche')) {
        accionFinal = 'uso_liberar_coche';
        datosFinales = { ...datosFinales, accion: 'uso_liberar_coche', tipo_accion: 'usar' };
      } else {
        const txtLista = (memoria.ultimo_mensaje_bot && String(memoria.ultimo_mensaje_bot).trim()) || `Responde con el número (1 a ${opciones.length}) para elegir el coche.`;
        accionFinal = 'conversar';
        datosFinales = { ...datosFinales, accion: 'conversar', respuesta_usuario: txtLista };
      }
    }
  }
}
else if (memoria.esperando_confirmacion === 'elegir_coche_liberar') {
  const pendientes = memoria.datos_pendientes || {};
  const opciones = pendientes.coches_mios || [];
  if (esNegacion) {
    accionFinal = 'conversar';
    datosFinales = { ...datosFinales, accion: 'conversar', respuesta_usuario: '✅ Vale, no libero ningún coche.', borrar_memoria: true };
  } else if (msg.includes('ambos') || msg.includes('los dos') || msg.includes('todos')) {
    accionFinal = 'uso_liberar_coche';
    datosFinales = { ...datosFinales, accion: 'uso_liberar_coche', tipo_accion: 'liberar', vehicle_ids: opciones.map(c => c.id), liberar_ambos: true };
  } else {
    const n = parseInt(msgRaw, 10);
    if (Number.isFinite(n) && n >= 1 && n <= opciones.length) {
      const c = opciones[n - 1];
      accionFinal = 'uso_liberar_coche';
      datosFinales = { ...datosFinales, accion: 'uso_liberar_coche', tipo_accion: 'liberar', vehicle_ids: [c.id], coche_nombre: c.name };
    } else {
      const match = opciones.find(o => norm(o.name).includes(msg) || msg.includes(norm(o.name)));
      if (match) {
        accionFinal = 'uso_liberar_coche';
        datosFinales = { ...datosFinales, accion: 'uso_liberar_coche', tipo_accion: 'liberar', vehicle_ids: [match.id], coche_nombre: match.name };
      } else if (msg.includes('liberar') && msg.includes('coche')) {
        accionFinal = 'uso_liberar_coche';
        datosFinales = { ...datosFinales, accion: 'uso_liberar_coche', tipo_accion: 'liberar' };
      } else {
        const txtLista = (memoria.ultimo_mensaje_bot && String(memoria.ultimo_mensaje_bot).trim()) || `Responde con el número (1 a ${opciones.length}) o "ambos" para liberar todos.`;
        accionFinal = 'conversar';
        datosFinales = { ...datosFinales, accion: 'conversar', respuesta_usuario: txtLista };
      }
    }
  }
}

// ===============================
// 1c) Confirmaciones USO/LIBERAR MÁQUINA
// ===============================
else if (memoria.esperando_confirmacion === 'confirmar_usar_maquina_cambio') {
  const pendientes = memoria.datos_pendientes || {};
  if (esNegacion) {
    accionFinal = 'conversar';
    datosFinales = { ...datosFinales, accion: 'conversar', respuesta_usuario: '✅ Vale, no cambio la máquina.', borrar_memoria: true };
  } else if (esConfirmacion) {
    accionFinal = 'uso_liberar_maquina';
    datosFinales = { ...datosFinales, accion: 'uso_liberar_maquina', tipo_accion: 'usar', tool_id: pendientes.tool_id, maquina_nombre: pendientes.maquina_name, user_id: pendientes.user_id, confirmar_cambio: true };
  } else {
    accionFinal = 'conversar';
    datosFinales = { ...datosFinales, accion: 'conversar', respuesta_usuario: '¿Quieres que asigne esa máquina a tu usuario? Responde sí o no.' };
  }
}
else if (memoria.esperando_confirmacion === 'elegir_maquina_usar') {
  const pendientes = memoria.datos_pendientes || {};
  const opciones = pendientes.maquinas_libres || [];
  if (esNegacion) {
    accionFinal = 'conversar';
    datosFinales = { ...datosFinales, accion: 'conversar', respuesta_usuario: '✅ Vale, no asigno ninguna máquina.', borrar_memoria: true };
  } else {
    const n = parseInt(msgRaw, 10);
    if (Number.isFinite(n) && n >= 1 && n <= opciones.length) {
      const m = opciones[n - 1];
      accionFinal = 'uso_liberar_maquina';
      datosFinales = { ...datosFinales, accion: 'uso_liberar_maquina', tipo_accion: 'usar', tool_id: m.id, user_id: pendientes.user_id, maquina_nombre: m.name };
    } else {
      const match = opciones.find(o => norm(o.name||'').includes(msg) || msg.includes(norm(o.name||'')));
      if (match) {
        accionFinal = 'uso_liberar_maquina';
        datosFinales = { ...datosFinales, accion: 'uso_liberar_maquina', tipo_accion: 'usar', tool_id: match.id, user_id: pendientes.user_id, maquina_nombre: match.name };
      } else if (msg.includes('usar') && (msg.includes('maquina') || msg.includes('herramienta'))) {
        accionFinal = 'uso_liberar_maquina';
        datosFinales = { ...datosFinales, accion: 'uso_liberar_maquina', tipo_accion: 'usar' };
      } else {
        const txtLista = (memoria.ultimo_mensaje_bot && String(memoria.ultimo_mensaje_bot).trim()) || `Responde con el número (1 a ${opciones.length}) para elegir la máquina.`;
        accionFinal = 'conversar';
        datosFinales = { ...datosFinales, accion: 'conversar', respuesta_usuario: txtLista };
      }
    }
  }
}
