// =============================================================================
// GUIA DE USO: intenta mapear TODAS las acciones del nodo Switch (misma "accion"
// en JSON) sin IA. La IA queda SOLO si no hay regla, empate, o heuristica dudosa.
// Con esperando_confirmacion: "conversar" y el nodo "Router de Acciones FIXED"
// aplica memoria (igual que si el agente devolviera conversar).
// Acciones del Switch no listadas abajo: registrar_tarea, elegir_tarea_imagen_previa,
// preparar_confirmacion_imagen_tarea_elegida, confirmacion_asociar_imagen -> flujo
// con memoria: se usan "conversar" y el Router aplica memoria (ver esperando_confirmacion).
// GUIA_VERSION: subir al añadir reglas o cambiar prioridades.
// =============================================================================
const GUIA_VERSION = 3;

const norm = (s) =>
  String(s ?? "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\s+/g, " ")
    .trim();

const raw = $json;
const msg = norm(raw.mensaje_usuario || "");
const orig = String(raw.mensaje_usuario_original || raw.mensaje_usuario || "").trim();
const nPalabras = msg ? msg.split(/\s+/).length : 0;

const Z = { travel_distance_km: 0, travel_time_hours: 0 };
const PROYECTO_DEFAULT = "Servicio de campo";

const outIa = (motivo) => [
  {
    ...raw,
    clasificador_rapido_necesita_ia: true,
    clasificador_rapido_motivo: motivo,
    clasificador_rapido_guia_version: GUIA_VERSION,
    clasificador_rapido_regla_id: null,
    clasificador_rapido_payload: null,
  },
];

const outLocal = (reglaId, payload) => [
  {
    ...raw,
    clasificador_rapido_necesita_ia: false,
    clasificador_rapido_motivo: "guia_parametrizada",
    clasificador_rapido_guia_version: GUIA_VERSION,
    clasificador_rapido_regla_id: reglaId,
    clasificador_rapido_payload: { ...Z, ...payload },
  },
];

if (!msg) return outIa("mensaje_vacio");

if (raw.esperando_confirmacion) {
  return outLocal("delega_router_conversar", {
    accion: "conversar",
    respuesta_usuario: "Procesando con el contexto guardado…",
  });
}

if (msg.length > 2400 || nPalabras > 260) return outIa("mensaje_muy_largo");

if ((orig.match(/\?/g) || []).length >= 4 && nPalabras > 50) return outIa("texto_muy_inquisitivo_largo");

// ----- helpers de extraccion (FSM / partes) ---------------------------------

function firstHours(m) {
  const a = m.match(/(\d+[\.,]\d+|\d+)\s*h(oras?)?\b/);
  if (a) return { v: parseFloat(a[1].replace(",", ".")), m: a[0] };
  const w = m.match(
    /\b(una|un|dos|tres|cuatro|cinco|seis|siete|ocho|nueve|diez|once|doce|media|cuarto)\s+horas?\b/,
  );
  if (!w) return null;
  const map = {
    una: 1,
    un: 1,
    dos: 2,
    tres: 3,
    cuatro: 4,
    cinco: 5,
    seis: 6,
    siete: 7,
    ocho: 8,
    nueve: 9,
    diez: 10,
    once: 11,
    doce: 12,
    media: 0.5,
    cuarto: 0.25,
  };
  return { v: map[w[1]] ?? null, m: w[0] };
}

function horasPresupuestadas(m) {
  if (!/(presupuest|hara\s+falta|vamos\s+a\s+necesitar|necesitare?mos|se\s+necesita|estim|aprox|diagnost)/.test(m)) return 0;
  const x = m.match(
    /(\d+[\.,]?\d*)\s*h(oras?)?(?=[^.]*(presupuest|falta|necesit|estim|aprox|diagnost|para))/,
  ) || m.match(/(presupuest|falta|necesit|estim|aprox)\D{0,30}(\d+[\.,]?\d*)\s*h/);
  if (x) {
    const n = x[2] || x[1];
    const f = parseFloat(String(n).replace(",", "."));
    return Number.isFinite(f) ? f : 0;
  }
  const f2 = m.match(
    /(\d+[\.,]?\d*)\s*h(oras?)?(?!.+(?:trabaj|dedic|imput))/,
  );
  if (f2) return parseFloat(f2[1].replace(",", ".")) || 0;
  return 0;
}

function parseProyectoTarea(m) {
  let proyecto = "";
  let tarea = "";
  const p1 = m.match(
    /proyecto\s+["']?([^"'\n]+?)(?=\s+tarea\b|\s+[:,]|\s+con\s+|\s+para\s+|$)/i,
  );
  if (p1) proyecto = p1[1].trim();
  const t1 = m.match(
    /tarea\s+["']?([^"'\n]+?)(?=\s+(?:\d|h\b|con|y|materi|torni|proyecto|descripcion|desc|km)|$)/i,
  );
  if (t1) tarea = t1[1].trim();
  if (!proyecto) {
    const p2 = m.match(
      /(?:en|del|en el)\s+proyecto\s+["']?([a-z0-9áéíóúñ][^,\n.]{1,50})/i,
    );
    if (p2) proyecto = p2[1].trim();
  }
  if (!tarea) {
    const t2 = m.match(
      /(?:en la|a la|la)\s+tarea\s+["']?([a-z0-9áéíóúñ][^,\n.]{1,50})/i,
    );
    if (t2) tarea = t2[1].trim();
  }
  return { proyecto, tarea };
}

function parseProductosLinea(m) {
  const out = [];
  const stopW = (s) => /^(horas?|h|proyecto|tarea|trabaj|dedic|imput|registr|parte|stock)$/i.test(s.trim());
  const chunk = m.replace(/y\s+(\d)/g, ", $1");
  const parts = chunk.split(/,|\s+y\s+(?=\d)/);
  for (const seg of parts) {
    const r = seg.match(
      /(\d+[\.,]?\d*)\s*(?:x|×|uds?)?\s*([a-z0-9áéíóúñ.\- ]{2,40})/i,
    );
    if (r) {
      const q = parseFloat(r[1].replace(",", "."));
      let nombre = (r[2] || "").replace(/\s+/g, " ").trim();
      if (nombre && !stopW(nombre) && q > 0 && q < 1e6)
        out.push({ nombre, cantidad: q });
    }
  }
  return out.slice(0, 30);
}

function hasMaterialIntent(m) {
  if (/(materi|torni|cable|stock|producto|consumi|repon|unidad|uds|bulto|kilo|litro|metro|tornill|junt|pieza|ud\.)/.test(m))
    return true;
  return parseProductosLinea(m).length > 0;
}

function isPresupuestoOEstim(m) {
  return /(presupuest|hara\s+falta|vamos\s+a\s+necesitar|necesitare?mos|estim|aprox|diagnost|para presupuest)/.test(
    m,
  );
}

// ----- Reglas: cubrir acciones alineadas con el Switch + registrar_horas (pre-Router) ----

