  },
  {
    id: "lopd",
    prior: 96,
    when: (m) => /(\blopd\b|firmar.*lopd|firma\s+lopd)/.test(m) && nPalabras < 30,
    go: () => ({ accion: "firmar_lopd", respuesta_usuario: "Consultando tareas para LOPD…" }),
  },
  {
    id: "parte_y_stock",
    prior: 94,
    when: (m) => {
      if (nPalabras > 120) return false;
      if (
        /(cuantas|cuanto|consulta|dime|resumen|ventas?|facturas?)\b.*(horas|dedic|proyecto)/.test(m) &&
        !/registr|imputa|anota|parte|material|materi|torni|stock/.test(m)
      )
        return false;
      const hPart = firstHours(m);
      const mat = hasMaterialIntent(m);
      const pres = isPresupuestoOEstim(m);
      if (!mat && !pres) return false;
      return !!(hPart || /(registr\w*|imput\w*|anot\w*|\bparte\b|stock|consumo|reponer|materi)/.test(m));
    },
    go: (m) => {
      const hp = firstHours(m);
      let horas = hp && hp.v > 0 ? hp.v : 0;
      if (!horas) {
        const g = m.match(/(\d+[\.,]?\d*)\s*h(oras?)?/);
        if (g) horas = parseFloat(g[1].replace(",", ".")) || 0;
      }
      const hpres = horasPresupuestadas(m) || 0;
      const diag = isPresupuestoOEstim(m) || (hpres > 0 && /diagnost|presupuest|necesit|estim|aprox/.test(m));
      const { proyecto, tarea } = parseProyectoTarea(m);
      const productos = parseProductosLinea(m);
      const dTexto = orig.slice(0, 500) || m.slice(0, 500);
      return {
        accion: "registrar_parte_y_stock",
        is_diagnosis_task: !!diag,
        diagnostico_detectado: !!diag,
        horas: diag && horas === 0 && hpres > 0 ? 0 : horas,
        horas_presupuestadas: hpres,
        proyecto: proyecto || PROYECTO_DEFAULT,
        tarea: tarea || "Trabajo de campo",
        descripcion: dTexto,
        productos: productos.length
          ? productos
          : hasMaterialIntent(m)
            ? []
            : [],
        tipo_accion_stock: /(consumi|gast|resta|descuent)/.test(m) ? "consumir" : undefined,
        cliente: "interno",
        respuesta_usuario:
          "Voy a preparar el parte (horas y/o materiales) con lo detectado. Comprueba o confirma en el siguiente paso.",
      };
    },
  },
  {
    id: "registrar_horas",
    prior: 80,
    when: (m) => {
      if (nPalabras > 80) return false;
      if (isPresupuestoOEstim(m) || hasMaterialIntent(m)) return false;
      if (!/(\d+[\.,]?\d*)\s*h(oras?)?|una|dos|tres|cuatro|cinco|seis|siete|ocho|nueve|diez|media|cuarto.*horas?/.test(m)) return false;
      if (!/(registr\w*|imput\w*|anot\w*|\bhoras?\b|parte(?!.+(material|stock|torni)))/.test(m)) return false;
      if (!/(proyecto|tarea)/.test(m)) return false;
      const h = firstHours(m) || m.match(/(\d+[\.,]?\d*)\s*h/);
      if (!h) return false;
      return true;
    },
    go: (m) => {
      const hp = firstHours(m);
      let horas = hp && hp.v > 0 ? hp.v : 0;
      if (!horas) {
        const g = m.match(/(\d+[\.,]?\d*)\s*h(oras?)?\b/);
        if (g) horas = parseFloat(g[1].replace(",", ".")) || 0;
      }
      const { proyecto, tarea } = parseProyectoTarea(m);
      return {
        accion: "registrar_horas",
        proyecto: proyecto || PROYECTO_DEFAULT,
        tarea: tarea || "Tarea",
        horas: horas || 0,
        descripcion: orig.slice(0, 400) || "Trabajo registrado",
        respuesta_usuario: `Registro de ${horas} h (proyecto/tarea detectados)…`,
      };
    },
  },
  {
    id: "compra_inventario",
    prior: 78,
    when: (m) =>
      nPalabras < 55 &&
      /(he\s+comprado|compr[eé]\s|compra\s+de|registrar\s+compra|nuevo\s+inventario|me\s+han\s+llegado|orden\s+de\s+compra)/.test(
        m,
      ) &&
      /\d/.test(m) &&
      !/presupuest\s+venta|ventas?\s+pedid/.test(m),
    go: (m) => ({
      accion: "registrar_compra_inventario",
      respuesta_usuario: "Procesando compra / inventario…",
    }),
  },
  {
    id: "fichaje_gps",
    prior: 90,
    when: (m, o) => {
      const c = o.match(/(-?\d{1,3}(?:\.\d+)?)\s*[,;\s]+\s*(-?\d{1,3}(?:\.\d+)?)/);
      if (!c) return false;
      const la = parseFloat(c[1]);
      const lo = parseFloat(c[2]);
      if (!Number.isFinite(la) || !Number.isFinite(lo) || Math.abs(la) > 90 || Math.abs(lo) > 180) return false;
      return /(fichaje|fichar|entrada|salida|check\s*in|check\s*out)/.test(m) && nPalabras < 60;
    },
    go: (m, o) => {
      const c = o.match(/(-?\d{1,3}(?:\.\d+)?)\s*[,;\s]+\s*(-?\d{1,3}(?:\.\d+)?)/);
      const la = parseFloat(c[1]);
      const lo = parseFloat(c[2]);
      let tf = "auto";
      if (/\bentrada\b/.test(m)) tf = "entrada";
      else if (/\bsalida\b/.test(m)) tf = "salida";
      return {
        accion: "registrar_fichaje",
        tipo_fichaje: tf,
        latitude: la,
        longitude: lo,
        respuesta_usuario: "Registrando fichaje…",
      };
    },
  },
  {
    id: "gasto",
    prior: 76,
    when: (m) => {
      const hasMoney = /(\d+[\.,]?\d+)\s*(€|eur|euros)\b/.test(m);
      return nPalabras < 45 && hasMoney && /(gasto|expens|apunte|pago)\b/.test(m);
    },
    go: (m, o) => {
      const g = m.match(/(\d+[\.,]?\d+)\s*(?:€|eur|euros)/);
      return {
        accion: "registrar_gasto",
        importe: parseFloat((g[1] || "0").replace(",", ".")) || 0,
        descripcion: o.slice(0, 200) || "Gasto",
        respuesta_usuario: "Registrando gasto…",
      };
    },
  },
  {
    id: "ventas",
    prior: 50,
    when: (m) => /\bventas?\b|\bpedidos?\b(?!.*detalle)/.test(m) && !/ventas?\s+.*\s+orden|orden\s*s\d/i.test(m),
    go: () => ({
      accion: "consultar_ventas",
      periodo_meses: null,
      periodo_semanas: null,
      periodo_dias: null,
      filtro_estado: null,
      cliente_nombre: null,
      comercial_nombre: null,
      partner_id: null,
      comercial_user_id: null,
      respuesta_usuario: "Consultando ventas…",
    }),
  },
  {
    id: "facturas",
    prior: 50,
    when: (m) => /\bfactur/.test(m),
    go: () => ({
      accion: "consultar_facturas",
      periodo_meses: null,
      periodo_semanas: null,
      periodo_dias: null,
      filtro_estado: null,
      cliente_nombre: null,
      comercial_nombre: null,
      partner_id: null,
      comercial_user_id: null,
      respuesta_usuario: "Consultando facturas…",
    }),
  },
  {
    id: "actividad",
    prior: 48,
    when: (m) =>
      nPalabras < 55 &&
      /(que\s+(ha\s+)?hecho|actividad|que\s+hice|que\s+hizo|mi\s+actividad|esta\s+semana|semana\s+pasada|este\s+mes|mes\s+pasado|hoy|ayer)/.test(
        m,
      ),
    go: (m) => {
      let periodo = "hoy";
      if (/\bayer\b/.test(m)) periodo = "ayer";
      else if (/esta\s+semana/.test(m)) periodo = "esta_semana";
      else if (/semana\s+pasada/.test(m)) periodo = "semana_pasada";
      else if (/este\s+mes/.test(m)) periodo = "este_mes";
      else if (/mes\s+pasado/.test(m)) periodo = "mes_pasado";
      else if (/\bhoy\b/.test(m)) periodo = "hoy";
      let usuario = "Usuario actual";
      const u = m.match(/(?:de|del|para)\s+([a-z0-9áéíóúñ]{2,24})/i);
      if (u && !/semana|mes|hoy|ayer|actividad|este|esta/.test(u[1])) usuario = u[1];
      return {
        accion: "consultar_actividad_usuario",
        usuario,
        periodo,
        respuesta_usuario: "Consultando actividad…",
      };
    },
  },
  {
    id: "consulta_horas_pt",
    prior: 46,
    when: (m) =>
      nPalabras < 60 &&
      /(cuantas|cuanto|tiempo)\s+(de\s+)?(horas|dedic|invert)/.test(m) &&
      !/registr\w*(\s+|\s*)/.test(m) &&
      !/parte(?!\s+de)/.test(m),
    go: (m) =>
      /\btarea\b/.test(m)
        ? {
            accion: "consultar_horas_tarea",
            proyecto: "",
            tarea: "",
            respuesta_usuario: "Consultando horas en tarea…",
          }
        : {
            accion: "consultar_horas_proyecto",
            proyecto: "",
            respuesta_usuario: "Consultando horas en proyecto…",
          },
  },
  {
    id: "estado_proyecto",
    prior: 44,
    when: (m) =>
      nPalabras < 70 &&
      /(estado|situacion|como\s+va|avance|progreso|etap|fase).{0,30}proyecto|proyectos?\s+en\s+(proceso|curso|hecho|nuev|finali)/.test(
        m,
      ),
    go: () => ({
      accion: "consultar_estado_proyecto",
      proyecto: "",
      incluir_registros: false,
      dias: 90,
      respuesta_usuario: "Consultando estado del proyecto…",
    }),
  },
  {
    id: "coche",
    prior: 38,
    when: (m) =>
      nPalabras < 40 &&
      /(usar|liberar|coger|asignar|devolver|dejar).{0,20}(coche|vehiculo)|\bcoche\b.*(liberar|usar|asigna)/.test(m),
    go: (m) => ({
      accion: "uso_liberar_coche",
      tipo_accion: /(liberar|devolver|dejar)/.test(m) ? "liberar" : "usar",
      coche: "",
      respuesta_usuario: "Gestionando coche…",
    }),
  },
  {
    id: "maquina",
    prior: 38,
    when: (m) =>
      nPalabras < 40 &&
      /(usar|liberar|coger|asignar|devolver|dejar).{0,22}(maquina|herramienta)|\b(herramienta|maquina)\b.*(usar|liberar)/.test(
        m,
      ),
    go: (m) => ({
      accion: "uso_liberar_maquina",
      tipo_accion: /(liberar|devolver|dejar)/.test(m) ? "liberar" : "usar",
      maquina: "",
      respuesta_usuario: "Gestionando maquina…",
    }),
  },
  {
    id: "conversar",
    prior: 4,
    when: (m) =>
      nPalabras <= 16 &&
      /^(hola|hi|buenos|buenas|gracias|ok|vale|genial|perfecto|adios|chao|bye|hasta|buen dia|buen fin)\b/.test(
        m,
      ) &&
      !/(registr|ventas?|factur|proyecto|tarea|horas|fich|gasto|compra|invent|lopd|maquina|coche|parte|stock|material|presupuest|dime|cuantas)/.test(
        m,
      ),
    go: () => ({ accion: "conversar", respuesta_usuario: "Dime en que te ayudo con Odoo." }),
  },
];

const hits = REGLAS.filter((r) => {
  try {
    return r.when(msg, orig);
  } catch {
    return false;
  }
});
if (hits.length === 0) return outIa("sin_mapeo_local_todas_las_excepciones");

const maxP = Math.max(...hits.map((h) => h.prior));
const best = hits.filter((h) => h.prior === maxP);
if (best.length > 1) return outIa("varias_reglas_empate_misma_prioridad");

const gana = best[0];
let body;
try {
  body = gana.go(msg, orig);
} catch (e) {
  return outIa("error_build_payload");
}
if (!body || typeof body !== "object" || !body.accion) return outIa("payload_invalido");

if (gana.id === "registrar_horas") {
  if (!(Number(body.horas) > 0) || !String(body.tarea || "").trim() || !String(body.proyecto || "").trim()) {
    return outIa("registrar_horas_incompleto");
  }
}

if (gana.id === "parte_y_stock") {
  const b = body;
  const prods = Array.isArray(b.productos) ? b.productos : [];
  const ok =
    Number(b.horas) > 0 ||
    Number(b.horas_presupuestadas) > 0 ||
    prods.length > 0 ||
    isPresupuestoOEstim(m);
  if (!ok) return outIa("parte_y_stock_incompleto");
}

return outLocal(gana.id, body);

// Emula la salida del AI Agent para Procesar Respuesta (JSON en output).
const p = $json.clasificador_rapido_payload;
const fallback = {
  accion: 'fallback',
  respuesta_usuario:
    'No pude resolver esto en modo rapido. Reformula o usa el agente cuando este disponible.',
  travel_distance_km: 0,
  travel_time_hours: 0,
};
const body = p && typeof p === 'object' ? p : fallback;
return [{ output: JSON.stringify(body) }];

