let mensaje = '';
let esAudio = false;
let tieneImagen = false;
let fileId = null;
let imagenFileId = null;
let imgData = null;

const nowIso = () => new Date().toISOString();

// =========================
// DETECTAR TELEGRAM
// =========================
if ($json.message && $json.message.chat) {
  const msg = $json.message;
  const chatId = msg.chat.id;
  const userId = msg.from?.id || chatId;
  const userName = msg.from?.first_name || msg.from?.username || 'Usuario';
  const caption = (msg.caption ?? '').trim();

  if (msg.text) {
    mensaje = msg.text.trim();
  } else if (msg.voice) {
    esAudio = true;
    fileId = msg.voice.file_id;
    mensaje = '[Mensaje de voz recibido. Transcribiendo...]';
  } else if (msg.document) {
    const d = msg.document;
    const isImageDoc = typeof d.mime_type === 'string' && d.mime_type.startsWith('image/');

    if (isImageDoc) {
      tieneImagen = true;
      imagenFileId = d.file_id;
      mensaje = caption ? caption : '[Imagen recibida sin texto]';

      imgData = {
        kind: 'document',
        file_id: d.file_id,
        file_unique_id: d.file_unique_id,
        file_size: d.file_size,
        file_name: d.file_name || null,
        mime_type: d.mime_type || null,
        caption: caption || null,
        message_id: msg.message_id,
        message_date_unix: msg.date || null,
        timestamp: nowIso(),
        from_chat_id: chatId,
        from_user_id: userId,
      };
    } else {
      mensaje = '[Documento recibido (no imagen)]';
    }
  } else if (msg.photo && Array.isArray(msg.photo) && msg.photo.length) {
    const photoData = msg.photo[msg.photo.length - 1];
    tieneImagen = true;
    imagenFileId = photoData.file_id;
    mensaje = caption ? caption : '[Imagen recibida sin texto]';

    imgData = {
      kind: 'photo',
      file_id: photoData.file_id,
      file_unique_id: photoData.file_unique_id,
      file_size: photoData.file_size,
      width: photoData.width,
      height: photoData.height,
      all_sizes: msg.photo,
      caption: caption || null,
      message_id: msg.message_id,
      message_date_unix: msg.date || null,
      timestamp: nowIso(),
      from_chat_id: chatId,
      from_user_id: userId,
    };
  } else if (msg.location && msg.location.latitude !== undefined && msg.location.longitude !== undefined) {
    const lat = msg.location.latitude;
    const lon = msg.location.longitude;

    mensaje = `fichar ubicacion: ${lat}, ${lon}`;
    tieneImagen = true;

    imgData = {
      kind: 'location',
      latitude: lat,
      longitude: lon,
      horizontal_accuracy: msg.location.horizontal_accuracy || null,
      heading: msg.location.heading || null,
      proximity_alert_radius: msg.location.proximity_alert_radius || null,
      live_period: msg.location.live_period || null,
      message_id: msg.message_id,
      message_date_unix: msg.date || null,
      timestamp: nowIso(),
      from_chat_id: chatId,
      from_user_id: userId,
    };
  } else {
    mensaje = '[Mensaje no soportado]';
  }

  return {
    plataforma: 'telegram',
    canal_respuesta: 'telegram',

    mensaje_usuario: mensaje,
    chat_id: chatId,
    user_id: userId,
    user_name: userName,
    timestamp: nowIso(),

    es_audio: esAudio,
    tiene_imagen: tieneImagen,
    file_id: fileId,
    imagen_file_id: imagenFileId,
    img_data: imgData,
  };
}

// =========================
// DETECTAR WHATSAPP
// =========================
// Soporta WhatsApp Trigger / webhook Meta típico
const waValue =
  $json.entry?.[0]?.changes?.[0]?.value ||
  $json.value ||
  {};

const waMsg =
  waValue.messages?.[0] ||
  $json.messages?.[0] ||
  null;

const waContact =
  waValue.contacts?.[0] ||
  $json.contacts?.[0] ||
  null;

if (waMsg) {
  const from = waMsg.from || waContact?.wa_id || null;
  const userName = waContact?.profile?.name || 'Usuario';
  const tipo = waMsg.type || 'text';

  if (tipo === 'text') {
    mensaje = waMsg.text?.body?.trim() || '';
  } else if (tipo === 'audio') {
    esAudio = true;
    fileId = waMsg.audio?.id || null;
    mensaje = '[Mensaje de voz recibido. Transcribiendo...]';
  } else if (tipo === 'image') {
    tieneImagen = true;
    imagenFileId = waMsg.image?.id || null;
    mensaje = waMsg.image?.caption?.trim() || '[Imagen recibida sin texto]';

    imgData = {
      kind: 'image',
      file_id: imagenFileId,
      mime_type: waMsg.image?.mime_type || null,
      sha256: waMsg.image?.sha256 || null,
      caption: waMsg.image?.caption || null,
      wa_message_id: waMsg.id || null,
      timestamp: nowIso(),
      from_chat_id: from,
      from_user_id: from,
    };
  } else if (tipo === 'document') {
    mensaje = waMsg.document?.caption?.trim() || '[Documento recibido]';
    fileId = waMsg.document?.id || null;
  } else if (tipo === 'location' && waMsg.location?.latitude !== undefined && waMsg.location?.longitude !== undefined) {
    const lat = Number(waMsg.location.latitude);
    const lon = Number(waMsg.location.longitude);

    mensaje = `fichar ubicacion: ${lat}, ${lon}`;
    tieneImagen = true;

    imgData = {
      kind: 'location',
      latitude: lat,
      longitude: lon,
      name: waMsg.location?.name || null,
      address: waMsg.location?.address || null,
      wa_message_id: waMsg.id || null,
      timestamp: nowIso(),
      from_chat_id: from,
      from_user_id: from,
    };
  } else {
    mensaje = `[Mensaje WhatsApp no soportado: ${tipo}]`;
  }

  return {
    plataforma: 'whatsapp',
    canal_respuesta: 'whatsapp',

    mensaje_usuario: mensaje,
    chat_id: from,           // lo reutilizas como destinatario para WhatsApp
