// ========= 4) FUNCIÓN UTC -> HORA MADRID =========
const convertirUTCaHoraLocal = (fechaString) => {
  if (!fechaString) return '00:00';

  try {
    const fechaUTC = new Date(fechaString + 'Z'); // Odoo suele venir sin zona; forzamos UTC
    return fechaUTC.toLocaleTimeString('es-ES', {
      hour: '2-digit',
      minute: '2-digit',
      timeZone: 'Europe/Madrid'
    });
  } catch (error) {
    console.log('❌ Error convirtiendo hora:', error);
    return '00:00';
  }
};

