  const usuario = e.user_id?.[1] || 'Sin asignar';
  agenda.push({
    origen: 'calendar',
    name: e.name,
    start: e.start,
    stop: e.stop,
    location: e.location || null,
    usuarios: [usuario],
  });
}

// B) Tareas planificadas
// IMPORTANTE: user_ids es many2many -> puede venir como array de IDs (dependiendo de Odoo)
// Si en tu respuesta viene como [[id, "Nombre"]] (raro en search_read), ajusta abajo.
// Aquí asumimos lo normal: user_ids: [1,2,3] y NO trae nombres.
// Pero tú has pedido fields: user_ids, así que solo tendrás IDs.
// => Solución práctica: si NO hay nombres, las agrupamos como "Asignado" genérico.
// Si quieres nombres reales: hay que pedir user_ids y hacer lookup en res.users (te lo monto si lo quieres).

for (const t of tareasPlanificadas) {
  const inicio = t.planned_date_begin || null;
  // En tu vista usan date_deadline como “fin” para el filtro; úsalo como stop
  const fin = t.date_deadline || null;

  // Location: cliente si existe
  const location = t.partner_id?.[1] || null;

  // Si user_ids trae nombres (no siempre), intentamos extraerlos:
  let usuarios = [];
  if (Array.isArray(t.user_ids) && t.user_ids.length > 0) {
    // Caso 1: user_ids = [1,2,3] (IDs)
    if (typeof t.user_ids[0] === 'number') {
      usuarios = ['Asignado (user_ids)']; // fallback sin nombres
    }
    // Caso 2: user_ids = [[id,"Nombre"], ...] (si tu Odoo lo devolviera así)
    else if (Array.isArray(t.user_ids[0])) {
      usuarios = t.user_ids.map(u => u?.[1]).filter(Boolean);
    }
  }

  if (usuarios.length === 0) usuarios = ['Sin asignar'];

  // Duplicar por usuario (si hay varios) para que aparezca bajo cada uno
  for (const u of usuarios) {
    agenda.push({
      origen: 'task',
      name: `🛠️ ${t.name}`,
      start: inicio,
      stop: fin,
      location,
      usuarios: [u],
    });
  }
}

// ========= 6) ORDENAR POR HORA =========
agenda.sort((a, b) => {
  const da = a.start ? new Date(a.start + 'Z').getTime() : 0;
  const db = b.start ? new Date(b.start + 'Z').getTime() : 0;
  return da - db;
});

