  resumen += `✅ No hay eventos ni tareas planificadas para hoy\n\n`;
} else {
  const agendaPorUsuario = {};

  for (const item of agenda) {
    const usuario = item.usuarios?.[0] || 'Sin asignar';
    if (!agendaPorUsuario[usuario]) agendaPorUsuario[usuario] = [];
    agendaPorUsuario[usuario].push(item);
  }

  for (const usuario of Object.keys(agendaPorUsuario)) {
    resumen += `👤 **${usuario}:**\n`;

    for (const item of agendaPorUsuario[usuario]) {
      const horaInicio = convertirUTCaHoraLocal(item.start);
      const horaFin = convertirUTCaHoraLocal(item.stop);

      resumen += `   🕐 ${horaInicio}-${horaFin}: ${item.name}`;
      if (item.location) resumen += ` 📍 ${item.location}`;
      resumen += `\n`;
    }

    resumen += `\n`;
  }
}

// --- ÓRDENES ---
