// ✅ CONSULTAR ÚLTIMO PARTE REAL EN ODOO (evita usar ID obsoleto de n8n)
const ultimo = $items('Buscar Último Horas ID', 0)[0].json;
const fallbackId = Number(ultimo.ultimo_horas_id);
const chatId = ultimo.chat_id;
const user_name = ultimo.user_name;

let odooUserId = null;
if (ultimo.user_id != null) {
  const u = typeof ultimo.user_id === 'object' ? ultimo.user_id?.[0] : ultimo.user_id;
  if (Number.isFinite(Number(u)) && Number(u) > 0) odooUserId = Number(u);
}

const db = 'mchecaazor-webinar3-main-30740598';
const pass = 'admin';
const url = 'https://mchecaazor-webinar3.odoo.com/jsonrpc';

let horasId = fallbackId;

try {
  const authBody = { jsonrpc: '2.0', method: 'call', params: { service: 'common', method: 'authenticate', args: [db, 'admin', pass, {}] }, id: 1 };
  const authRes = await this.helpers.httpRequest({ method: 'POST', url, body: authBody, json: true });
  const uid = authRes?.result;
  if (!uid) throw new Error('No UID');

  if (odooUserId) {
    const searchBody = { jsonrpc: '2.0', method: 'call', params: { service: 'object', method: 'execute_kw', args: [db, uid, pass, 'account.analytic.line', 'search_read', [[['user_id', '=', odooUserId]], ['id', 'create_date']], { order: 'create_date desc', limit: 1 }] }, id: 2 };
    const searchRes = await this.helpers.httpRequest({ method: 'POST', url, body: searchBody, json: true });
    const rows = searchRes?.result || [];
    if (rows.length && rows[0].id) {
      horasId = Number(rows[0].id);
    }
  } else if (ultimo.odoo_user) {
    const loginBody = { jsonrpc: '2.0', method: 'call', params: { service: 'object', method: 'execute_kw', args: [db, uid, pass, 'res.users', 'search_read', [[['login', '=', ultimo.odoo_user]]], { fields: ['id'], limit: 1 }] }, id: 3 };
    const loginRes = await this.helpers.httpRequest({ method: 'POST', url, body: loginBody, json: true });
    const users = loginRes?.result || [];
    if (users.length && users[0].id) {
      const uId = Number(users[0].id);
      const searchBody = { jsonrpc: '2.0', method: 'call', params: { service: 'object', method: 'execute_kw', args: [db, uid, pass, 'account.analytic.line', 'search_read', [[['user_id', '=', uId]], ['id', 'create_date']], { order: 'create_date desc', limit: 1 }] }, id: 4 };
      const searchRes = await this.helpers.httpRequest({ method: 'POST', url, body: searchBody, json: true });
      const rows = searchRes?.result || [];
      if (rows.length && rows[0].id) horasId = Number(rows[0].id);
    }
  }
} catch (e) {
  console.error('Consultar Último Parte Odoo:', e.message);
}

return { ultimo_horas_id: horasId, chat_id: chatId, user_id: ultimo.user_id, user_name };

// ✅ PREPARAR ADJUNTO DIRECTO (PARTE)

const datosBase = $items('Construir URL Descarga Parte', 0)[0].json;
const ultimo = $items('Consultar Último Parte Odoo', 0)[0].json;

const horasId = Number(ultimo.ultimo_horas_id);
if (!Number.isFinite(horasId) || horasId <= 0) {
  throw new Error('No hay ultimo_horas_id válido para adjuntar.');
}

// 1) Intento: binario en el item actual
let bin = null;
let binKeys = Object.keys($binary || {});
if (binKeys.length) {
  bin = $binary[binKeys[0]];
}

// 2) Fallback: leer binario del nodo HTTP Descargar Imagen REAL
if (!bin || !bin.data) {
  const httpItems = $items('Descargar Imagen REAL (PARTE)', 0, 0) || [];
  if (httpItems.length && httpItems[0].binary) {
    const httpBinKeys = Object.keys(httpItems[0].binary);
    if (httpBinKeys.length) {
      bin = httpItems[0].binary[httpBinKeys[0]];
    }
  }
}

// 3) Si aún no hay binario, error con debug
if (!bin || !bin.data) {
  const debug = {
    tieneBinaryActual: !!$binary,
    keysBinaryActual: Object.keys($binary || {}),
    download_url: datosBase.download_url || null,
  };
  throw new Error('No se encontraron datos binarios del archivo descargado | DEBUG: ' + JSON.stringify(debug));
}

// 4) Convertir base64 → Buffer
const archivoBinario = Buffer.from(bin.data, 'base64');

// 5) Detectar mimetype/extensión
let mimetype = bin.mimeType || 'image/jpeg';
let extension = bin.fileExtension || null;

if (!extension) {
  const sig = archivoBinario.slice(0, 8).toString('hex').toUpperCase();
  if (sig.startsWith('89504E47')) { mimetype = 'image/png'; extension = 'png'; }
  else if (sig.startsWith('FFD8FF')) { mimetype = 'image/jpeg'; extension = 'jpg'; }
  else { extension = mimetype.includes('png') ? 'png' : 'jpg'; }
}

// 6) Preparar adjunto Odoo
const archivoBase64 = archivoBinario.toString('base64');
const ts = new Date().toISOString().replace(/[:.]/g, '-');
const nombreArchivo = `Parte-${horasId}-${ts}.${extension}`;

const db = 'mchecaazor-webinar3-main-30740598';
const uid = 2; // admin

const consultaAdjunto = {
  jsonrpc: "2.0",
  method: "call",
  params: {
    service: "object",
    method: "execute_kw",
    args: [
      db,
      uid,
      "admin",
      "ir.attachment",
      "create",
      [{
        name: nombreArchivo,
        datas: archivoBase64,
        res_model: "account.analytic.line",
        res_id: horasId,
        mimetype: mimetype,
        type: "binary"
      }]
    ]
  },
  id: Math.floor(Math.random() * 1000000)
};

return {
  ...datosBase,
  horas_id: horasId,
  imagen_lista_para_subir: true,
  imagen_adjuntada: true,
  consulta_adjunto: consultaAdjunto,
  archivo_info: {
    nombre: nombreArchivo,
    mimetype,
    tamaño: archivoBinario.length
  }
};

