async function firstExistingAnalyticLineId(uid, orderedIds) {
  const uniq = [];
  const seen = new Set();
  for (const raw of orderedIds) {
    const id = Number(raw);
    if (!Number.isFinite(id) || id <= 0 || seen.has(id)) continue;
    seen.add(id);
    uniq.push(id);
  }
  if (!uniq.length) return null;
  const sr = await http({
    jsonrpc: '2.0',
    method: 'call',
    params: {
      service: 'object',
      method: 'execute_kw',
      args: [
        db,
        uid,
        pass,
        'account.analytic.line',
        'search_read',
        [[['id', 'in', uniq]]],
        { fields: ['id'], limit: 200 },
      ],
    },
    id: 60,
  });
  const found = new Set((Array.isArray(sr?.result) ? sr.result : []).map((r) => Number(r.id)));
  for (const id of uniq) {
    if (found.has(id)) return id;
  }
  return null;
}

function odooUtcSinceMinutes(min) {
  const d = new Date(Date.now() - min * 60000);
  return d.toISOString().replace('T', ' ').slice(0, 19);
}

async function ultimoParteId(uid, odooUserId) {
