function parseParteIdDesdeTextoBot(s) {
  if (s === undefined || s === null) return null;
  const t = String(s);
  const patterns = [
    /ID del registro[^0-9]{0,20}(\d+)/i,
    /firma-parte\/(\d+)/i,
    /web#id=(\d+)[\s\S]{0,160}account[.]analytic[.]line/i,
  ];
  for (const re of patterns) {
    const m = t.match(re);
    if (m) {
      const n = Number(m[1]);
      if (Number.isFinite(n) && n > 0) return n;
    }
  }
  return null;
}

async function resolverTimesheetVincular(uid, x) {
  const cands = [];
  const add = (v) => {
    const n = Number(v);
    if (Number.isFinite(n) && n > 0) cands.push(n);
  };
  add(memRow.ultimo_horas_id);
  add(x.ultimo_horas_id);
  try {
    const row = safeFirst('Consultar Memoria PostgreSQL');
    add(row?.ultimo_horas_id);
    add(parseParteIdDesdeTextoBot(row?.ultimo_mensaje_bot));
  } catch (_) {}
  add(parseParteIdDesdeTextoBot(memRow.ultimo_mensaje_bot));

  const seen = new Set();
  const ordered = [];
  for (const id of cands) {
    if (seen.has(id)) continue;
    seen.add(id);
    ordered.push(id);
  }

  const existing = await firstExistingAnalyticLineId(uid, ordered);
  if (existing) return existing;

  const odooUserId = await resolveOdooUserId(uid, x);
  return await ultimoParteId(uid, odooUserId);
}

