// NODO UNIFICADOR - PREPARAR DATOS POSTGRESQL CON BÚSQUEDA ACTIVA
const timestampActual = new Date().toISOString();

// ✅ RAMA COMPRA INV: Telegram/WhatsApp devuelven solo la respuesta de la API; recuperar contexto del nodo anterior
let compraInvCtx = {};
try {
  const rc = $('Registro Compra Inventario Odoo').first()?.json;
  if (rc && String(rc.esperando_confirmacion || '').startsWith('compra_inv_')) {
    compraInvCtx = rc;
  }
} catch (e) {
  console.log('ℹ️ Sin contexto Registro Compra Inventario Odoo:', e.message);
}

// Detectar si viene del flujo de evento incompleto
let respuestaBot = compraInvCtx.respuesta_usuario || $json.texto_final || $json.texto || $json.text || $json.respuesta_usuario || 'Respuesta procesada';

// Si viene de evento incompleto, usar mensaje específico
if ($json.esperando_confirmacion === 'crear_evento_calendario' && $json.datos_pendientes) {
  respuestaBot = 'faltan datos';
} else if ($json.ultimo_mensaje_bot) {
  respuestaBot = $json.ultimo_mensaje_bot;
}

console.log('🔄 === PREPARAR DATOS POSTGRESQL - BÚSQUEDA ACTIVA ===');
console.log('📥 Datos recibidos directamente:', JSON.stringify($json, null, 2));

// FUNCIÓN PARA BUSCAR DATOS DEL USUARIO EN NODOS ANTERIORES
function buscarDatosUsuario() {
  const nodosABuscar = [
    'Router de Acciones FIXED',
    'Procesar Respuesta',
    'Preparar Datos AI Agent',
    'Obtener Chat ID',
    'Extraer Datos'
  ];
  for (const nombreNodo of nodosABuscar) {
    try {
      const datos = $(nombreNodo).first().json;
      if (datos && datos.chat_id && datos.chat_id !== 'unknown') {
        console.log(`✅ Datos encontrados en: ${nombreNodo}`);
        return {
          chat_id: datos.chat_id,
          user_id: datos.user_id || datos.chat_id,
          user_name: datos.user_name || 'Usuario',
          mensaje_original: datos.mensaje_usuario || datos.mensaje_original || 'mensaje no disponible',
          fuente: nombreNodo,
          es_fallback: datos.es_fallback === true
        };
      }
    } catch (e) {
      console.log(`⚠️ No se pudo acceder a ${nombreNodo}:`, e.message);
    }
  }
  return null;
}

// INTENTAR OBTENER DATOS DEL USUARIO
let datosUsuario = {
  chat_id: compraInvCtx.chat_id ?? $json.chat_id,
  user_id: compraInvCtx.user_id ?? $json.user_id,
  user_name: compraInvCtx.user_name ?? $json.user_name,
  mensaje_original: $json.mensaje_usuario || $json.mensaje_original,
  es_fallback: $json.es_fallback === true
};

// Si no tenemos chat_id válido, buscar en nodos anteriores
if (!datosUsuario.chat_id || datosUsuario.chat_id === 'unknown') {
  console.log('🔍 Chat ID no válido, buscando en nodos anteriores...');
  const datosBuscados = buscarDatosUsuario();
  if (datosBuscados) {
    datosUsuario = datosBuscados;
    console.log(`✅ Datos recuperados desde: ${datosBuscados.fuente}`);
  } else {
    console.log('❌ No se encontraron datos válidos del usuario');
    datosUsuario = {
      chat_id: 0,
      user_id: 0,
      user_name: 'unknown',
      mensaje_original: 'mensaje no disponible',
      fuente: 'fallback',
      es_fallback: true
    };
  }
}

console.log('👤 DATOS FINALES DEL USUARIO:', {
  chat_id: datosUsuario.chat_id,
  user_id: datosUsuario.user_id,
  user_name: datosUsuario.user_name,
  fuente: datosUsuario.fuente || 'directo',
  es_fallback: datosUsuario.es_fallback === true
});

// PRESERVAR esperando_confirmacion cuando venimos de máquina/coche esperando respuesta del usuario
let esperandoPreservar = null;
let datosPendientesPreservar = null;
const estadosPreservarMaq = ['elegir_maquina_usar', 'elegir_maquina_liberar', 'confirmar_usar_maquina_cambio'];
const estadosPreservarCoche = ['confirmar_usar_coche_cambio', 'elegir_coche_usar', 'elegir_coche_liberar'];
try {
  const procMaq = $('Procesar Uso Liberar Maquina').first().json;
  if (procMaq?.esperando_confirmacion && estadosPreservarMaq.includes(procMaq.esperando_confirmacion)) {
    esperandoPreservar = procMaq.esperando_confirmacion;
    datosPendientesPreservar = JSON.stringify({ maquinas_mias: procMaq.maquinas_mias || [], maquinas_libres: procMaq.maquinas_libres || [], tool_id: procMaq.tool_id, maquina_name: procMaq.maquina_name, user_id: procMaq.user_id });
  }
} catch {}
if (!esperandoPreservar) {
  try {
    const procCoche = $('Procesar Uso Liberar Coche').first().json;
    if (procCoche?.esperando_confirmacion && estadosPreservarCoche.includes(procCoche.esperando_confirmacion)) {
      esperandoPreservar = procCoche.esperando_confirmacion;
      datosPendientesPreservar = JSON.stringify({ coches_mios: procCoche.coches_mios || [], coches_libres: procCoche.coches_libres || [], vehicle_id: procCoche.vehicle_id, vehicle_name: procCoche.vehicle_name, partner_id: procCoche.partner_id });
    }
  } catch {}
}

// CREAR REGISTRO PARA POSTGRESQL (preservar esperando_confirmacion si máquina/coche esperando respuesta)
const registroPostgreSQL = {
  chat_id: parseInt(datosUsuario.chat_id) || 0,
  user_id: parseInt(datosUsuario.user_id) || 0,
  user_name: datosUsuario.user_name === 'unknown' ? null : datosUsuario.user_name,
  proyecto_anterior: null,
  tarea_anterior: null,
  ultima_accion: 'conversar',
  esperando_confirmacion: esperandoPreservar,
  esperando_respuesta: null,
  ultimo_mensaje_bot: respuestaBot,
  mensaje_usuario: datosUsuario.mensaje_original === 'mensaje no disponible' ? null : datosUsuario.mensaje_original,
  datos_pendientes: datosPendientesPreservar,
  historial: JSON.stringify([{
    timestamp: timestampActual,
    usuario: datosUsuario.mensaje_original,
    bot: respuestaBot,
    accion: 'conversar'
  }]),
  historial_conversacion: JSON.stringify([{
    timestamp: timestampActual,
    contenido: datosUsuario.mensaje_original,
    tipo: 'usuario'
  }, {
    timestamp: timestampActual,
    contenido: respuestaBot,
    tipo: 'bot'
  }]),
  // Propagar al post-descontar
  es_fallback: datosUsuario.es_fallback === true
};

const _ecCompra = compraInvCtx.esperando_confirmacion || $json.esperando_confirmacion;
const _dpCompra = compraInvCtx.datos_pendientes ?? $json.datos_pendientes;
if (_ecCompra && String(_ecCompra).startsWith('compra_inv_')) {
  registroPostgreSQL.esperando_confirmacion = _ecCompra;
  registroPostgreSQL.datos_pendientes =
    typeof _dpCompra === 'string' ? _dpCompra : JSON.stringify(_dpCompra || {});
}
if (compraInvCtx.limpiar_confirmacion_compra_inv === true || $json.limpiar_confirmacion_compra_inv === true) {
  registroPostgreSQL.esperando_confirmacion = null;
  registroPostgreSQL.datos_pendientes = null;
}

console.log('📤 REGISTRO FINAL PARA POSTGRESQL:', {
  chat_id: registroPostgreSQL.chat_id,
  user_id: registroPostgreSQL.user_id,
  user_name: registroPostgreSQL.user_name,
  es_fallback: registroPostgreSQL.es_fallback
});

return [registroPostgreSQL];

const esFallback = $json.es_fallback === true;
const userId = Number($json.user_id || 0);

// Si es fallback, no descontar
return {
  ...$json,
  descuento_necesario: !esFallback,
  user_id_descuento: userId
};

// Preparar consulta de actividad temporal por usuario
const datosAI = $json;
const uid = $('Autenticar Odoo').item.json.result;
const nombreUsuario = datosAI.usuario;
const periodo = datosAI.periodo;

console.log('🔍 Consultando actividad de usuario:', nombreUsuario, 'en período:', periodo);

// Validar datos
if (!uid) throw new Error('No se pudo obtener el UID de autenticación');
if (!nombreUsuario) throw new Error('No se encontró el nombre del usuario');

// Si no hay período, enviar mensaje de ayuda por Telegram
if (!periodo) {
  const mensajeAyuda = `❌ **Período no especificado**\n\n` +
    `👤 **Usuario:** "${nombreUsuario}"\n\n` +
    `Para consultar la actividad de un usuario, necesitas especificar el período de tiempo.\n\n` +
    `📅 **Períodos disponibles:**\n` +
    `• **hoy** - actividad de hoy\n` +
    `• **ayer** - actividad de ayer\n` +
    `• **esta semana** - actividad de esta semana\n` +
    `• **semana pasada** - actividad de la semana pasada\n` +
    `• **este mes** - actividad de este mes\n` +
    `• **mes pasado** - actividad del mes pasado\n\n` +
    `💡 **Ejemplos:**\n` +
    `• "¿qué ha hecho ${nombreUsuario} hoy?"\n` +
    `• "actividad de ${nombreUsuario} esta semana"\n` +
    `• "¿cuántas horas trabajó ${nombreUsuario} este mes?"`;

  return {
    accion: 'enviar_mensaje_directo',
    chat_id: datosAI.chat_id,
    texto: mensajeAyuda
  };
}

// Calcular fechas según el período
const ahora = new Date();
let fechaInicio, fechaFin;

switch(periodo) {
  case 'hoy':
    fechaInicio = new Date(ahora.getFullYear(), ahora.getMonth(), ahora.getDate());
    fechaInicio.setHours(0, 0, 0, 0);
    fechaFin = new Date(ahora.getFullYear(), ahora.getMonth(), ahora.getDate() + 1);
    fechaFin.setHours(0, 0, 0, 0);
    break;
  case 'ayer':
    fechaInicio = new Date(ahora.getFullYear(), ahora.getMonth(), ahora.getDate() - 1);
    fechaInicio.setHours(0, 0, 0, 0);
    fechaFin = new Date(ahora.getFullYear(), ahora.getMonth(), ahora.getDate());
    fechaFin.setHours(0, 0, 0, 0);
    break;
  case 'esta_semana':
    // Calcular el lunes de esta semana (getDay(): 0=domingo, 1=lunes, etc.)
    const diasDesdeInicioSemana = ahora.getDay() === 0 ? 6 : ahora.getDay() - 1; // Si es domingo, retroceder 6 días
    fechaInicio = new Date(ahora.getFullYear(), ahora.getMonth(), ahora.getDate() - diasDesdeInicioSemana);
    fechaInicio.setHours(0, 0, 0, 0); // Inicio del día
    fechaFin = new Date(ahora.getFullYear(), ahora.getMonth(), ahora.getDate() + 1);
    fechaFin.setHours(0, 0, 0, 0); // Inicio del día siguiente
    break;
  case 'semana_pasada':
    // Calcular el lunes de la semana pasada
    const diasDesdeInicioSemanaAnterior = ahora.getDay() === 0 ? 6 : ahora.getDay() - 1;
    const lunesSemanaAnterior = new Date(ahora.getFullYear(), ahora.getMonth(), ahora.getDate() - diasDesdeInicioSemanaAnterior - 7);
    fechaInicio = new Date(lunesSemanaAnterior);
    fechaInicio.setHours(0, 0, 0, 0);
    fechaFin = new Date(lunesSemanaAnterior.getFullYear(), lunesSemanaAnterior.getMonth(), lunesSemanaAnterior.getDate() + 7);
    fechaFin.setHours(0, 0, 0, 0);
    break;
  case 'este_mes':
    fechaInicio = new Date(ahora.getFullYear(), ahora.getMonth(), 1);
    fechaInicio.setHours(0, 0, 0, 0);
    fechaFin = new Date(ahora.getFullYear(), ahora.getMonth() + 1, 1);
    fechaFin.setHours(0, 0, 0, 0);
    break;
  case 'mes_pasado':
    fechaInicio = new Date(ahora.getFullYear(), ahora.getMonth() - 1, 1);
    fechaInicio.setHours(0, 0, 0, 0);
    fechaFin = new Date(ahora.getFullYear(), ahora.getMonth(), 1);
    fechaFin.setHours(0, 0, 0, 0);
    break;
  case 'mes_nombre':
    // Para consultas de mes específico por nombre (ej: "enero", "febrero", etc.)
    // Por defecto usar el mes actual si no se puede determinar el mes específico
    fechaInicio = new Date(ahora.getFullYear(), ahora.getMonth(), 1);
    fechaInicio.setHours(0, 0, 0, 0);
    fechaFin = new Date(ahora.getFullYear(), ahora.getMonth() + 1, 1);
    fechaFin.setHours(0, 0, 0, 0);
    break;
  default:
    throw new Error('Período no válido: ' + periodo);
}

// Formatear fechas para Odoo (YYYY-MM-DD)
const formatearFecha = (fecha) => {
  return fecha.toISOString().split('T')[0];
};

const fechaInicioStr = formatearFecha(fechaInicio);
const fechaFinStr = formatearFecha(fechaFin);

console.log('📅 Fecha actual:', ahora.toISOString());
console.log('📅 Día de la semana:', ahora.getDay(), '(0=domingo)');
console.log('📅 Rango de fechas calculado:', fechaInicioStr, 'a', fechaFinStr);
console.log('📅 FechaInicio completa:', fechaInicio.toISOString());
console.log('📅 FechaFin completa:', fechaFin.toISOString());

// Determinar el mejor término de búsqueda
let terminoBusqueda = nombreUsuario;

// Mapeo específico para palabras clave comunes
const mapeoNombres = {
  'administrador': 'administrator',
  'admin': 'administrator',
  'gerente': 'manager',
  'desarrollador': 'developer',
  'consultor': 'consultant',
  'diseñador': 'designer'
};

const nombreLower = nombreUsuario.toLowerCase();
if (mapeoNombres[nombreLower]) {
  terminoBusqueda = mapeoNombres[nombreLower];
  console.log('🔄 Mapeando:', nombreUsuario, '→', terminoBusqueda);
}

console.log('🔍 Término de búsqueda final:', terminoBusqueda);

// Buscar usando el término más apropiado con búsqueda flexible
const buscarUsuario = {
  jsonrpc: "2.0",
  method: "call",
  params: {
    service: "object",
    method: "execute_kw",
    args: [
      "mchecaazor-webinar3-main-30740598",
      uid,
      "admin",
      "hr.employee",
      "search_read",
      [
        [
          ["name", "ilike", `%${terminoBusqueda}%`]
        ]
      ],
      {
        fields: ["id", "name", "user_id"],
        limit: 20
      }
    ]
  }
};

console.log('🔍 Primero buscando usuario exacto:', JSON.stringify(buscarUsuario, null, 2));

return {
  ...datosAI,
  payload: JSON.stringify(buscarUsuario),
  fechaInicio: fechaInicioStr,
  fechaFin: fechaFinStr,
  periodoTexto: periodo.replace('_', ' '),
  paso: 'buscar_usuario'
};

// Formatear respuesta de actividad temporal por usuario
const datosOriginales = $('Procesar Búsqueda Usuario').item.json;
const actividadData = $json.result || [];

const nombreUsuario = datosOriginales.usuario;
const usuarioEncontrado = datosOriginales.usuarioEncontrado || nombreUsuario;
const periodo = datosOriginales.periodoTexto;
const fechaInicio = datosOriginales.fechaInicio;
const fechaFin = datosOriginales.fechaFin;

console.log('📊 Formateando respuesta para usuario:', usuarioEncontrado);
console.log('📊 Registros encontrados:', actividadData.length);

if (!actividadData || actividadData.length === 0) {
  let textoError = `❌ **Sin actividad registrada**\n\n`;
  textoError += `👤 **Usuario:** "${usuarioEncontrado}"\n`;
  textoError += `📅 **Período:** ${periodo} (${fechaInicio} a ${fechaFin})\n\n`;
  textoError += `No se encontraron registros de tiempo para este usuario en el período especificado.\n\n`;
  textoError += `💡 **Sugerencias:**\n`;
  textoError += `• Verifica que el nombre del usuario sea correcto\n`;
  textoError += `• Intenta con un período más amplio\n`;
  textoError += `• Usa /listar usuarios para ver los usuarios disponibles`;

  return {
    chat_id: datosOriginales.chat_id,
    texto: textoError
  };
}

// Calcular estadísticas
let totalHoras = 0;
const actividadPorProyecto = {};
const actividadPorTarea = {};
const actividadPorDia = {};
const usuarioReal = actividadData[0].user_id[1];

actividadData.forEach(registro => {
  const horas = parseFloat(registro.unit_amount || 0);
  totalHoras += horas;

  // Agrupar por proyecto
  const proyecto = registro.project_id ? registro.project_id[1] : 'Sin proyecto';
  if (!actividadPorProyecto[proyecto]) {
    actividadPorProyecto[proyecto] = { horas: 0, registros: 0 };
  }
  actividadPorProyecto[proyecto].horas += horas;
  actividadPorProyecto[proyecto].registros++;

  // Agrupar por tarea
  const tarea = registro.task_id ? registro.task_id[1] : 'Sin tarea específica';
  if (!actividadPorTarea[tarea]) {
    actividadPorTarea[tarea] = { horas: 0, registros: 0 };
  }
  actividadPorTarea[tarea].horas += horas;
  actividadPorTarea[tarea].registros++;

  // Agrupar por día
  const dia = registro.date;
  if (!actividadPorDia[dia]) {
    actividadPorDia[dia] = { horas: 0, registros: 0 };
  }
  actividadPorDia[dia].horas += horas;
  actividadPorDia[dia].registros++;
});

// Construir respuesta
let texto = `⏰ **Actividad de ${usuarioReal}**\n\n`;
texto += `📅 **Período:** ${periodo} (${fechaInicio} a ${fechaFin})\n\n`;
texto += `📊 **Resumen:**\n`;
texto += `• Total de horas: ${totalHoras.toFixed(2)}h\n`;
texto += `• Registros: ${actividadData.length}\n`;
texto += `• Promedio diario: ${(totalHoras / Object.keys(actividadPorDia).length).toFixed(2)}h\n\n`;

// Mostrar proyectos trabajados
const proyectos = Object.entries(actividadPorProyecto)
  .sort(([,a], [,b]) => b.horas - a.horas);

if (proyectos.length > 0) {
  texto += `🏗️ **Proyectos trabajados:**\n`;
  proyectos.forEach(([proyecto, datos]) => {
    texto += `• ${proyecto}: ${datos.horas.toFixed(2)}h (${datos.registros} registros)\n`;
  });
  texto += `\n`;
}

// Mostrar tareas principales
const tareas = Object.entries(actividadPorTarea)
  .sort(([,a], [,b]) => b.horas - a.horas)
  .slice(0, 5);

if (tareas.length > 0) {
  texto += `🎯 **Principales tareas:**\n`;
  tareas.forEach(([tarea, datos], index) => {
    texto += `${index + 1}. ${tarea}: ${datos.horas.toFixed(2)}h\n`;
  });
  texto += `\n`;
}

// Mostrar actividad por días
const dias = Object.entries(actividadPorDia)
  .sort(([a], [b]) => new Date(b) - new Date(a))
  .slice(0, 7);

if (dias.length > 0) {
  texto += `📅 **Actividad diaria:**\n`;
  dias.forEach(([dia, datos]) => {
    const fecha = new Date(dia).toLocaleDateString('es-ES');
    texto += `• ${fecha}: ${datos.horas.toFixed(2)}h (${datos.registros} registros)\n`;
  });
}

return {
  chat_id: datosOriginales.chat_id,
  texto: texto
};

// Procesar resultado de búsqueda de usuarios y preparar consulta de actividad
const datosOriginales = $('Preparar Consulta Actividad Usuario').item.json;
const usuariosBuscados = $json.result || [];

const nombreUsuario = datosOriginales.usuario;
const fechaInicio = datosOriginales.fechaInicio;
const fechaFin = datosOriginales.fechaFin;
const uid = $('Autenticar Odoo').item.json.result;

console.log('👥 Usuarios encontrados:', usuariosBuscados.length);
console.log('👥 Lista de usuarios:', usuariosBuscados.map(u => u.name));

if (!usuariosBuscados || usuariosBuscados.length === 0) {
  // No se encontró el usuario
  const textoError = `❌ **Usuario no encontrado**\n\n` +
    `👤 **Usuario buscado:** "${nombreUsuario}"\n\n` +
    `No se encontró ningún usuario con ese nombre.\n\n` +
    `💡 **Sugerencias:**\n` +
    `• Verifica que el nombre del usuario sea correcto\n` +
    `• Intenta con solo el nombre sin apellidos\n` +
    `• Intenta con variaciones como "admin", "administrador", etc.`;

  return {
    accion: 'enviar_mensaje_directo',
    chat_id: datosOriginales.chat_id,
    texto: textoError
  };
}

// Buscar la mejor coincidencia
let usuarioSeleccionado = usuariosBuscados[0];

// Buscar coincidencia exacta (sin distinguir mayúsculas/minúsculas)
const coincidenciaExacta = usuariosBuscados.find(user => 
  user.name.toLowerCase() === nombreUsuario.toLowerCase()
);

if (coincidenciaExacta) {
  usuarioSeleccionado = coincidenciaExacta;
  console.log('✅ Coincidencia exacta encontrada:', usuarioSeleccionado.name);
} else {
  console.log('⚠️ No hay coincidencia exacta, usando primera opción:', usuarioSeleccionado.name);
}

console.log('👤 Empleado seleccionado:', usuarioSeleccionado.name, 'Employee ID:', usuarioSeleccionado.id, 'User ID:', usuarioSeleccionado.user_id);

// Verificar que el empleado tenga un user_id asociado
if (!usuarioSeleccionado.user_id) {
  const textoError = `❌ **Empleado sin usuario asociado**\n\n` +
    `👤 **Empleado encontrado:** "${usuarioSeleccionado.name}"\n\n` +
