const MAX = 3800;

// parte por líneas para no romper Markdown a mitad de una línea
const lines = String(texto || '').split('\n');

const chunks = [];
let buf = '';

for (const line of lines) {
  // si una sola línea es enorme, la troceamos a pelo
  if (line.length > MAX) {
    if (buf) { chunks.push(buf); buf = ''; }
    for (let i = 0; i < line.length; i += MAX) {
      chunks.push(line.slice(i, i + MAX));
    }
    continue;
  }

  const next = buf ? (buf + '\n' + line) : line;

  if (next.length > MAX) {
    if (buf) chunks.push(buf);
    buf = line;
  } else {
    buf = next;
  }
}
if (buf) chunks.push(buf);

