  if (!html) return '• No especificados';

  const txt = String(html)
    .replace(/<\/li>\s*<li[^>]*>/gi, '\n• ')
    .replace(/<li[^>]*>/gi, '• ')
    .replace(/<\/li>/gi, '')
    .replace(/<\/?(ul|ol)[^>]*>/gi, '')
    .replace(/<\/?(strong|b|em|i|u|ins|s|strike|del|p|div|span|h1|h2|h3|h4|h5)[^>]*>/gi, '')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<[^>]+>/g, '')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();

  return txt ? txt : '• No especificados';
};

