  modo: 'elegir_tarea_multiple',
  tareas_opciones: tareasOpciones,
  datos_parte: datosParte,                   // ✅ ya incluye transcripción
  cliente_buscado: $json.cliente_buscado,
  db: normalizado.db,
  uid_admin: normalizado.uid || 2,
  pass_admin: 'admin',
