  odoo_user_id: normalizado.odoo_user_id || null,
};

return {
  chat_id: chatId,
  user_id: $json.user_id || 0,
  user_name: $json.user_name || 'Usuario',
  esperando_confirmacion: 'elegir_tarea_multiple',
  ultimo_mensaje_bot: $json.mensaje || '¿Cuál tarea deseas?',
  datos_pendientes: JSON.stringify(datospendientes),

  // ✅ opcional: por si quieres ver en tabla
  mensaje_usuario: transcripcionOriginal,

  historial: JSON.stringify([]),
  historial_conversacion: JSON.stringify([]),

  plataforma: $json.plataforma || $node["Normalizar Parte+Materiales FSM"]?.json?.plataforma || 'telegram',
canal_respuesta: $json.plataforma || $node["Normalizar Parte+Materiales FSM"]?.json?.plataforma || 'telegram',
};

// Guardar memoria para confirmar tarea única
const chatId = $json.chat_id;
const normalizado = $node["Normalizar Parte+Materiales FSM"]?.json || {};

const transcripcionOriginal =
  $json.transcripcion_original ||
  $json.datos_parte?.transcripcion_original ||
  normalizado.transcripcion_original ||
  normalizado.parte_en_memoria?.transcripcion_original ||
  '';

const datosParte = {
  ...($json.datos_parte || {}),
  transcripcion_original: transcripcionOriginal,
  mensaje_usuario_original: transcripcionOriginal,
};

const pendientes = {
  modo: 'confirmar_tarea_unica',
  tarea_id: $json.tarea_id,
  tarea_nombre: $json.tarea_nombre,
  proyecto_id: $json.proyecto_id,
  proyecto_nombre: $json.proyecto_nombre,
  datos_parte: $json.datos_parte, // ✅ ya trae is_diagnosis_task/ticket_type/horas_presupuestadas
  db: normalizado.db,
  uid_admin: normalizado.uid || 2,
  pass_admin: 'admin',
  odoo_user: normalizado.odoo_user || '',
  odoo_user_id: normalizado.odoo_user_id || null,
};

return [{
  json: {
    chat_id: chatId,
    user_id: pendientes.odoo_user_id || 0,
    user_name: pendientes.odoo_user || 'Usuario',
    esperando_confirmacion: 'confirmar_tarea_unica',
    ultimo_mensaje_bot: $json.mensaje || '¿Confirmas?',
    datos_pendientes: JSON.stringify(pendientes),

    // ✅ opcional: guardarlo también en campo plano
    mensaje_usuario: transcripcionOriginal,

    historial: JSON.stringify([]),
    historial_conversacion: JSON.stringify([]),

    plataforma: $json.plataforma || $node["Normalizar Parte+Materiales FSM"]?.json?.plataforma || 'telegram',
canal_respuesta: $json.plataforma || $node["Normalizar Parte+Materiales FSM"]?.json?.plataforma || 'telegram',
  }
}];

const safeFirstJson = (nodeName) => {
  try {
    const arr = $items(nodeName, 0);
    return arr && arr[0] ? arr[0].json : null;
  } catch (e) {
    return null; // nodo no ejecutado o no existe en esta rama
