      resumen_creado: {
        proyecto: regNode.proyecto ?? ctx.proyecto ?? base.proyecto ?? extraerPartnerNode.result?.[0]?.project_id?.[1] ?? null,
        proyecto_id: ctx.proyecto_id ?? regNode.project_id ?? extraerPartnerNode.result?.[0]?.project_id?.[0] ?? null,
        tarea: regNode.tarea ?? ctx.tarea ?? base.tarea ?? extraerPartnerNode.result?.[0]?.name ?? null,
        tarea_id: regNode.task_id ?? ctx.task_id ?? extraerPartnerNode.result?.[0]?.id ?? null,
        horas: regNode.horas ?? ctx.horas ?? base.horas ?? 0,
        horas_id: Number.isFinite(horasId) ? horasId : (ctx.horas_id ?? null),
        descripcion: regNode.descripcion ?? ctx.descripcion ?? base.descripcion ?? null,
        fecha: ctx.fecha_hoy ?? base.fecha_hoy ?? new Date().toISOString().split('T')[0],
        db: regNode.db ?? ctx.db ?? base.db ?? null,
        uid: regNode.uid ?? ctx.uid ?? base.uid ?? null,
      }
    }
  };
});

