const base = (() => { try { return $('Procesar Confirmacion Asociar Imagen').first().json || {}; } catch { return {}; } })();
const ok = $json.success === true;
const msg = String($json.message || '');

if (ok) {
  return {
    ...base,
    ...$json,
    chat_id: String(base.chat_id || $json.chat_id || ''),
    plataforma: base.plataforma || $json.plataforma || 'telegram',
    canal_respuesta: base.canal_respuesta || base.plataforma || $json.canal_respuesta || 'telegram',
    accion: 'conversar',
    respuesta_usuario: 'OK. Imagen asociada correctamente en Odoo y vinculada a la tarea.',
    limpiar_confirmacion: true,
    borrar_memoria: true,
    esperando_confirmacion: null,
    datos_pendientes: null,
  };
}

return {
  ...base,
  ...$json,
  chat_id: String(base.chat_id || $json.chat_id || ''),
  plataforma: base.plataforma || $json.plataforma || 'telegram',
  canal_respuesta: base.canal_respuesta || base.plataforma || $json.canal_respuesta || 'telegram',
  accion: 'conversar',
  respuesta_usuario: `ERROR: Odoo no pudo asociar la imagen (${msg || 'sin detalle'}).`,
};

// CONSULTA RESUMEN VENTAS (sale.order) Y FACTURAS CLIENTE (account.move)
// Filtros opcionales: cliente (partner), comercial (vendedor), periodo, estado
const x = $json || {};

const safeFirst = (name) => {
  try {
    return $items(name, 0)?.[0]?.json ?? null;
  } catch {
    return null;
  }
};
const prep = safeFirst('Preparar Datos AI Agent') || {};
const baseMsg = String(prep.mensaje_usuario_original || prep.mensaje_usuario || x.mensaje_original || '').trim();
const msgNorm = baseMsg
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '');

const db = 'mchecaazor-webinar3-main-30740598';
const pass = 'admin';
const url = 'https://mchecaazor-webinar3.odoo.com/jsonrpc';

const http = async (body) => this.helpers.httpRequest({ method: 'POST', url, body, json: true });

async function odooUid() {
  const authRes = await http({
    jsonrpc: '2.0',
    method: 'call',
    params: { service: 'common', method: 'authenticate', args: [db, 'admin', pass, {}] },
    id: 1,
  });
  return authRes?.result || null;
}

async function searchCount(uid, model, domain) {
  const res = await http({
    jsonrpc: '2.0',
    method: 'call',
    params: {
      service: 'object',
      method: 'execute_kw',
      args: [db, uid, pass, model, 'search_count', [domain]],
    },
    id: Math.floor(Math.random() * 1e9),
  });
  if (res?.error) {
    const msg = res.error.data?.message || res.error.message || JSON.stringify(res.error);
    throw new Error(String(msg));
  }
  return Number(res?.result) || 0;
}

async function searchRead(uid, model, domain, fields, limit = 12) {
  const res = await http({
    jsonrpc: '2.0',
    method: 'call',
    params: {
      service: 'object',
      method: 'execute_kw',
      args: [db, uid, pass, model, 'search_read', [domain], { fields, limit }],
    },
    id: Math.floor(Math.random() * 1e9),
  });
  if (res?.error) {
    const msg = res.error.data?.message || res.error.message || JSON.stringify(res.error);
    throw new Error(String(msg));
  }
  return Array.isArray(res?.result) ? res.result : [];
}

function pad2(n) {
  return String(n).padStart(2, '0');
}
function toOdooTs(d) {
  return `${d.getFullYear()}-${pad2(d.getMonth() + 1)}-${pad2(d.getDate())} ${pad2(d.getHours())}:${pad2(d.getMinutes())}:${pad2(d.getSeconds())}`;
}

function normName(s) {
  return String(s || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function extractClienteComercialFromMessage(raw) {
  const t = String(raw || '');
  let cliente = '';
  let comercial = '';
  const stop =
    /\s+(?:últim|ultim|meses|mes\b|semanas|semana|d[ií]as|dia\b|este|ayer|hoy|borrador|confirm|cancel|enviad|factur|pedid|orden|ventas?|facturas?|cliente|comercial|vendedor)\b/i;
  const reCliente =
    /(?:^|[\s,;])(?:cliente|del\s+cliente|de\s+el\s+cliente)\s+([^,\n]+?)(?=\s+(?:últim|ultim|mes|semana|d[ií]a|este|borrador|confirm|cancel|venta|factura|comercial|vendedor|cliente)\b|$)/i;
  const reComercial =
    /(?:^|[\s,;])(?:comercial|vendedor|del\s+comercial|de\s+el\s+comercial)\s+([^,\n]+?)(?=\s+(?:últim|ultim|mes|semana|d[ií]a|este|borrador|confirm|cancel|venta|factura|cliente|comercial|vendedor)\b|$)/i;
  const mc = t.match(reCliente);
  if (mc) cliente = mc[1].trim().replace(/\.+$/g, '');
  const mo = t.match(reComercial);
  if (mo) comercial = mo[1].trim().replace(/\.+$/g, '');
  return { cliente, comercial };
}

function parsePeriodFromText(text) {
  const t = String(text || '').toLowerCase();
  let meses = null;
  let semanas = null;
  let dias = null;
  const mMes = t.match(/(\d+)\s*mes(?:es)?/);
  if (mMes) meses = Math.min(120, Math.max(1, parseInt(mMes[1], 10)));
  const mSem = t.match(/(\d+)\s*semanas?/);
  if (!meses && mSem) semanas = Math.min(520, Math.max(1, parseInt(mSem[1], 10)));
  const mDia = t.match(/(\d+)\s*d[ií]as?/);
  if (!meses && !semanas && mDia) dias = Math.min(3650, Math.max(1, parseInt(mDia[1], 10)));
  if (/ultim[oa]s?\s+12\s*meses/.test(t) || /ultimo\s+año/.test(t) || /ultimo\s+ano/.test(t)) meses = 12;
  if (/ultim[oa]s?\s+6\s*meses/.test(t)) meses = 6;
  if (/ultim[oa]s?\s+3\s*meses/.test(t)) meses = 3;
  if (/ultima\s+semana/.test(t) || /semana\s+pasada/.test(t)) semanas = 1;
  if (/ultimos?\s+7\s*d[ií]as/.test(t)) dias = 7;
  if (/ultimos?\s+30\s*d[ií]as/.test(t)) dias = 30;
  if (/este\s+mes/.test(t)) meses = 1;
  if (/este\s+año/.test(t) || /este\s+ano/.test(t)) {
    const now = new Date();
    meses = now.getMonth() + 1;
  }
  return { meses, semanas, dias };
}

function parseEstadoVenta(t) {
  const s = String(t || '').toLowerCase();
  if (/caducad|vencid.*presup|validez\s+venc/.test(s)) return 'caducadas';
  if (/completad|confirmad|pedido\s+confirm|venta\s+cerrad/.test(s)) return 'sale';
  if (/borrador/.test(s)) return 'draft';
  if (/cancelad|anulad/.test(s)) return 'cancel';
  if (/enviad/.test(s)) return 'sent';
  return null;
}

function parseEstadoFactura(t) {
  const s = String(t || '').toLowerCase();
  if (/vencid|impag|moros|overdue/.test(s)) return 'vencidas_impagas';
  if (/completad|contabiliz|publicad|postead/.test(s)) return 'posted';
  if (/borrador/.test(s)) return 'draft';
  if (/cancelad|anulad/.test(s)) return 'cancel';
  return null;
}

async function resolvePartnerId(uid, query) {
  const q = String(query || '').trim();
  if (q.length < 2) return { id: null, label: '', ambiguous: null, error: null };
  let rows = [];
  try {
    rows = await searchRead(
      uid,
      'res.partner',
      ['|', '|', ['name', 'ilike', q], ['complete_name', 'ilike', q], ['ref', 'ilike', q]],
      ['id', 'name', 'complete_name'],
      15,
    );
  } catch (_) {
    rows = await searchRead(uid, 'res.partner', ['|', ['name', 'ilike', q], ['ref', 'ilike', q]], ['id', 'name'], 15);
  }
  if (!rows.length) {
    return {
      id: null,
      label: '',
      ambiguous: null,
      error: `No encontré ningún contacto que coincida con «${q}». Prueba con más texto del nombre.`,
    };
  }
  const nq = normName(q);
  const exact = rows.find((r) => normName(r.name) === nq || normName(r.complete_name || r.name) === nq);
  if (exact) return { id: exact.id, label: exact.complete_name || exact.name, ambiguous: null, error: null };
  if (rows.length === 1) return { id: rows[0].id, label: rows[0].complete_name || rows[0].name, ambiguous: null, error: null };
  return {
    id: null,
    label: '',
    ambiguous: rows.slice(0, 8).map((r) => r.complete_name || r.name),
    error: null,
  };
}

async function resolveSalesUserId(uid, query) {
  const q = String(query || '').trim();
  if (q.length < 2) return { id: null, label: '', ambiguous: null, error: null };
  const domain = ['|', ['name', 'ilike', q], ['login', 'ilike', q]];
  const rows = await searchRead(uid, 'res.users', domain, ['id', 'name', 'login'], 15);
  if (!rows.length) {
    return { id: null, label: '', ambiguous: null, error: `No encontré ningún usuario/comercial «${q}» en Odoo.` };
  }
  const nq = normName(q);
  const exact = rows.find((r) => normName(r.name) === nq || normName(r.login || '') === nq);
  if (exact) return { id: exact.id, label: exact.name || exact.login, ambiguous: null, error: null };
  if (rows.length === 1) return { id: rows[0].id, label: rows[0].name || rows[0].login, ambiguous: null, error: null };
  return {
    id: null,
    label: '',
    ambiguous: rows.slice(0, 8).map((r) => `${r.name} (${r.login})`),
    error: null,
  };
}

function buildInvoiceUserDomain(salesUserId, useInvoiceUserField) {
  if (salesUserId == null) return [];
  return [useInvoiceUserField ? 'invoice_user_id' : 'user_id', '=', salesUserId];
}

const chatId = x.chat_id ?? prep.chat_id;
const plataforma = String(x.plataforma || prep.plataforma || 'telegram').toLowerCase();

const baseOut = {
  ...x,
  chat_id: chatId,
  user_id: x.user_id ?? prep.user_id,
  user_name: x.user_name ?? prep.user_name,
  plataforma,
  canal_respuesta: plataforma,
  accion: 'conversar',
};

try {
  const uid = await odooUid();
  if (!uid) {
    return { ...baseOut, respuesta_usuario: '❌ No pude autenticar con Odoo.' };
  }

  const accion = String(x.accion || '');
  const msg = baseMsg;

  const parsedCC = extractClienteComercialFromMessage(msg);
  let clienteNombre = String(x.cliente_nombre || x.cliente || '').trim() || parsedCC.cliente;
  let comercialNombre = String(x.comercial_nombre || x.comercial || x.vendedor || '').trim() || parsedCC.comercial;

  let partnerId = x.partner_id != null && Number(x.partner_id) > 0 ? Number(x.partner_id) : null;
  let salesUserId = x.comercial_user_id != null && Number(x.comercial_user_id) > 0 ? Number(x.comercial_user_id) : null;

  let partnerLabel = '';
  if (partnerId == null && clienteNombre) {
    const rp = await resolvePartnerId(uid, clienteNombre);
    if (rp.error) {
      return { ...baseOut, respuesta_usuario: `❌ ${rp.error}` };
    }
    if (rp.ambiguous) {
      return {
        ...baseOut,
        respuesta_usuario:
          `❓ Hay varios contactos parecidos a «${clienteNombre}». Refina el nombre o elige:\n` +
          rp.ambiguous.map((n, i) => `${i + 1}. ${n}`).join('\n'),
      };
    }
    partnerId = rp.id;
    partnerLabel = rp.label;
  } else if (partnerId != null) {
    const pr = await searchRead(uid, 'res.partner', [['id', '=', partnerId]], ['id', 'name', 'complete_name'], 1);
    partnerLabel = pr[0] ? pr[0].complete_name || pr[0].name : `ID ${partnerId}`;
  }

  let salesLabel = '';
  if (salesUserId == null && comercialNombre) {
    const ru = await resolveSalesUserId(uid, comercialNombre);
    if (ru.error) {
      return { ...baseOut, respuesta_usuario: `❌ ${ru.error}` };
    }
    if (ru.ambiguous) {
      return {
        ...baseOut,
        respuesta_usuario:
          `❓ Hay varios comerciales parecidos a «${comercialNombre}». Refina el nombre:\n` +
          ru.ambiguous.map((n, i) => `${i + 1}. ${n}`).join('\n'),
      };
    }
    salesUserId = ru.id;
    salesLabel = ru.label;
  } else if (salesUserId != null) {
    const ur = await searchRead(uid, 'res.users', [['id', '=', salesUserId]], ['id', 'name', 'login'], 1);
    salesLabel = ur[0] ? ur[0].name || ur[0].login : `Usuario #${salesUserId}`;
  }

  let meses = x.periodo_meses != null ? Number(x.periodo_meses) : null;
  let semanas = x.periodo_semanas != null ? Number(x.periodo_semanas) : null;
  let dias = x.periodo_dias != null ? Number(x.periodo_dias) : null;
  if (!Number.isFinite(meses) || meses <= 0) meses = null;
  if (!Number.isFinite(semanas) || semanas <= 0) semanas = null;
  if (!Number.isFinite(dias) || dias <= 0) dias = null;

  const fromText = parsePeriodFromText(msgNorm);
  if (meses == null && fromText.meses != null) meses = fromText.meses;
  if (semanas == null && fromText.semanas != null) semanas = fromText.semanas;
  if (dias == null && meses == null && semanas == null && fromText.dias != null) dias = fromText.dias;

  const hasta = new Date();
  let desde = new Date(hasta);
  if (meses != null) desde.setMonth(desde.getMonth() - meses);
  else if (semanas != null) desde.setDate(desde.getDate() - semanas * 7);
  else if (dias != null) desde.setDate(desde.getDate() - dias);
  else desde = null;

  const hastaStr = toOdooTs(hasta);
  const desdeStr = desde ? toOdooTs(desde) : null;
  const desdeDay = desdeStr ? desdeStr.slice(0, 10) : null;
  const hastaDay = hastaStr.slice(0, 10);

  const periodoLabel =
    meses != null
      ? `últimos ${meses} mes(es)`
      : semanas != null
        ? `últimas ${semanas} semana(s)`
        : dias != null
          ? `últimos ${dias} día(s)`
          : 'todo el histórico';

  const filtroExtra = [];
  if (partnerId != null) filtroExtra.push(['partner_id', '=', partnerId]);
  if (salesUserId != null) filtroExtra.push(['user_id', '=', salesUserId]);

  let filtroRaw = x.filtro_estado != null ? String(x.filtro_estado).trim().toLowerCase() : '';
  if (filtroRaw === 'completada' || filtroRaw === 'completadas' || filtroRaw === 'confirmada' || filtroRaw === 'confirmado') {
    if (accion === 'consultar_facturas') filtroRaw = 'posted';
    else filtroRaw = 'sale';
  }

  const headerFiltros = [];
  if (partnerLabel) headerFiltros.push(`Cliente: *${partnerLabel}*`);
  if (salesLabel) headerFiltros.push(`Comercial: *${salesLabel}*`);

  if (accion === 'consultar_ventas') {
    let filtroV = filtroRaw || parseEstadoVenta(msg);
    const dateDom =
      desdeStr != null
        ? [
            ['date_order', '>=', desdeStr],
            ['date_order', '<=', hastaStr],
          ]
        : [];

    const states = [
      { key: 'draft', label: 'Borrador (presupuesto)' },
      { key: 'sent', label: 'Presupuesto enviado' },
      { key: 'sale', label: 'Pedido confirmado' },
      { key: 'cancel', label: 'Cancelado' },
    ];

    const counts = {};
    let total = 0;
    for (const st of states) {
      const dom = [...dateDom, ...filtroExtra, ['state', '=', st.key]];
      const c = await searchCount(uid, 'sale.order', dom);
      counts[st.key] = c;
      total += c;
    }

    let caducadas = null;
    try {
      const domCad = [
        ...dateDom,
        ...filtroExtra,
        ['validity_date', '!=', false],
        ['validity_date', '<', hastaDay],
        ['state', 'in', ['draft', 'sent']],
      ];
      caducadas = await searchCount(uid, 'sale.order', domCad);
    } catch (_) {
      caducadas = null;
    }

    const lines = [];
    lines.push(`📊 *Ventas (órdenes)* — ${periodoLabel}`);
    if (headerFiltros.length) {
      lines.push(headerFiltros.join(' · '));
    }

    if (filtroV === 'caducadas') {
      lines.push('');
      lines.push('Filtro: *presupuestos caducados* (validez pasada, borrador o enviado)');
      lines.push(`• Cantidad: *${caducadas == null ? 'N/D (sin campo validity_date en Odoo)' : caducadas}*`);
    } else if (filtroV && ['draft', 'sent', 'sale', 'cancel'].includes(filtroV)) {
      const st = states.find((s) => s.key === filtroV);
      lines.push('');
      lines.push(`Filtro: *${st ? st.label : filtroV}*`);
      lines.push(`• Pedidos: *${counts[filtroV] ?? 0}*`);
    } else {
      lines.push('');
      lines.push('Por estado:');
      for (const st of states) lines.push(`• ${st.label}: *${counts[st.key]}*`);
      lines.push(`• *Total pedidos:* ${total}`);
      if (caducadas != null) lines.push(`• Presupuestos caducados (validez): *${caducadas}*`);
    }

    return { ...baseOut, respuesta_usuario: lines.join('\n') };
  }

  if (accion === 'consultar_facturas') {
    let filtroF = filtroRaw || parseEstadoFactura(msg);
    const baseInv = [['move_type', '=', 'out_invoice']];

    let useInvUser = true;
    const filtroPartner = partnerId != null ? [['partner_id', '=', partnerId]] : [];

    function buildFactDomains(salesField) {
      const userDom = salesUserId != null ? [[salesField, '=', salesUserId]] : [];
      const filtroInv = [...filtroPartner, ...userDom];
      const domDraft =
        desdeStr != null
          ? [...baseInv, ...filtroInv, ['state', '=', 'draft'], ['create_date', '>=', desdeStr], ['create_date', '<=', hastaStr]]
          : [...baseInv, ...filtroInv, ['state', '=', 'draft']];
      const domPosted =
        desdeDay != null
          ? [...baseInv, ...filtroInv, ['state', '=', 'posted'], ['invoice_date', '>=', desdeDay], ['invoice_date', '<=', hastaDay]]
          : [...baseInv, ...filtroInv, ['state', '=', 'posted']];
      const domCancel =
        desdeStr != null
          ? [...baseInv, ...filtroInv, ['state', '=', 'cancel'], ['create_date', '>=', desdeStr], ['create_date', '<=', hastaStr]]
          : [...baseInv, ...filtroInv, ['state', '=', 'cancel']];
      return { filtroInv, domDraft, domPosted, domCancel };
    }

    let { filtroInv, domDraft, domPosted, domCancel } = buildFactDomains('invoice_user_id');
    let cDraft;
    let cPosted;
    let cCancel;
    try {
      cDraft = await searchCount(uid, 'account.move', domDraft);
      cPosted = await searchCount(uid, 'account.move', domPosted);
      cCancel = await searchCount(uid, 'account.move', domCancel);
    } catch (e1) {
      if (salesUserId != null && String(e1.message || '').includes('invoice_user_id')) {
        useInvUser = false;
        const b = buildFactDomains('user_id');
        filtroInv = b.filtroInv;
        domDraft = b.domDraft;
        domPosted = b.domPosted;
        domCancel = b.domCancel;
        cDraft = await searchCount(uid, 'account.move', domDraft);
        cPosted = await searchCount(uid, 'account.move', domPosted);
        cCancel = await searchCount(uid, 'account.move', domCancel);
      } else {
        throw e1;
      }
    }

    let cVenc = null;
    const salesField = useInvUser ? 'invoice_user_id' : 'user_id';
    try {
      const userDom = salesUserId != null ? [[salesField, '=', salesUserId]] : [];
      const filtroVdom = [...filtroPartner, ...userDom];
      const domV = [
        ...baseInv,
        ...filtroVdom,
        ['state', '=', 'posted'],
        ['payment_state', 'not in', ['paid', 'reversed']],
        ['invoice_date_due', '!=', false],
        ['invoice_date_due', '<', hastaDay],
      ];
      if (desdeDay != null) {
        domV.push(['invoice_date', '>=', desdeDay]);
        domV.push(['invoice_date', '<=', hastaDay]);
      }
      cVenc = await searchCount(uid, 'account.move', domV);
    } catch (e2) {
      if (salesUserId != null && String(e2.message || '').includes('invoice_user_id')) {
        try {
          const userDom = [['user_id', '=', salesUserId]];
          const filtroVdom = [...filtroPartner, ...userDom];
          const domV = [
            ...baseInv,
            ...filtroVdom,
            ['state', '=', 'posted'],
            ['payment_state', 'not in', ['paid', 'reversed']],
            ['invoice_date_due', '!=', false],
            ['invoice_date_due', '<', hastaDay],
          ];
          if (desdeDay != null) {
            domV.push(['invoice_date', '>=', desdeDay]);
            domV.push(['invoice_date', '<=', hastaDay]);
          }
          cVenc = await searchCount(uid, 'account.move', domV);
        } catch (_) {
          cVenc = null;
        }
      } else {
        cVenc = null;
      }
    }

    const lines = [];
    lines.push(`📑 *Facturas de cliente* — ${periodoLabel}`);
    if (headerFiltros.length) {
      lines.push(headerFiltros.join(' · '));
    }

    if (filtroF === 'vencidas_impagas') {
      lines.push('');
      lines.push('Filtro: *publicadas, no pagadas, con vencimiento anterior a hoy*');
      lines.push(`• Cantidad: *${cVenc == null ? 'N/D' : cVenc}*`);
    } else if (filtroF === 'draft') {
      lines.push('');
      lines.push('Filtro: *borrador*');
      lines.push(`• Cantidad: *${cDraft}*`);
    } else if (filtroF === 'posted') {
      lines.push('');
      lines.push('Filtro: *contabilizadas / publicadas*');
      lines.push(`• Cantidad: *${cPosted}*`);
    } else if (filtroF === 'cancel') {
      lines.push('');
      lines.push('Filtro: *canceladas*');
      lines.push(`• Cantidad: *${cCancel}*`);
    } else {
      lines.push('');
      lines.push('Por estado:');
      lines.push(`• Borrador: *${cDraft}*`);
      lines.push(`• Contabilizadas: *${cPosted}*`);
      lines.push(`• Canceladas: *${cCancel}*`);
      lines.push(`• Vencidas e impagadas (fecha vencimiento < hoy): *${cVenc == null ? 'N/D' : cVenc}*`);
    }

    return { ...baseOut, respuesta_usuario: lines.join('\n') };
  }

  return {
    ...baseOut,
    respuesta_usuario: '❌ Acción de consulta no reconocida.',
  };
} catch (e) {
  console.error('Consultar Ventas Facturas:', e);
  return {
    ...baseOut,
    respuesta_usuario: `❌ Error al consultar Odoo: ${e.message || e}`,
  };
}

