  },
];

if (!msg) return outIa("mensaje_vacio");

if (raw.esperando_confirmacion) {
  return outLocal("delega_router_conversar", {
    accion: "conversar",
    respuesta_usuario: "Procesando con el contexto guardado…",
  });
}

if (msg.length > 2400 || nPalabras > 260) return outIa("mensaje_muy_largo");

if ((orig.match(/\?/g) || []).length >= 4 && nPalabras > 50) return outIa("texto_muy_inquisitivo_largo");

// ----- helpers de extraccion (FSM / partes) ---------------------------------

function firstHours(m) {
  const a = m.match(/(\d+[\.,]\d+|\d+)\s*h(oras?)?\b/);
  if (a) return { v: parseFloat(a[1].replace(",", ".")), m: a[0] };
  const w = m.match(
    /\b(una|un|dos|tres|cuatro|cinco|seis|siete|ocho|nueve|diez|once|doce|media|cuarto)\s+horas?\b/,
  );
  if (!w) return null;
  const map = {
    una: 1,
    un: 1,
    dos: 2,
    tres: 3,
    cuatro: 4,
    cinco: 5,
    seis: 6,
    siete: 7,
    ocho: 8,
    nueve: 9,
    diez: 10,
    once: 11,
    doce: 12,
    media: 0.5,
    cuarto: 0.25,
  };
  return { v: map[w[1]] ?? null, m: w[0] };
}

function horasPresupuestadas(m) {
  if (!/(presupuest|hara\s+falta|vamos\s+a\s+necesitar|necesitare?mos|se\s+necesita|estim|aprox|diagnost)/.test(m)) return 0;
  const x = m.match(
    /(\d+[\.,]?\d*)\s*h(oras?)?(?=[^.]*(presupuest|falta|necesit|estim|aprox|diagnost|para))/,
  ) || m.match(/(presupuest|falta|necesit|estim|aprox)\D{0,30}(\d+[\.,]?\d*)\s*h/);
  if (x) {
    const n = x[2] || x[1];
    const f = parseFloat(String(n).replace(",", "."));
    return Number.isFinite(f) ? f : 0;
  }
  const f2 = m.match(
    /(\d+[\.,]?\d*)\s*h(oras?)?(?!.+(?:trabaj|dedic|imput))/,
  );
  if (f2) return parseFloat(f2[1].replace(",", ".")) || 0;
  return 0;
}

function parseProyectoTarea(m) {
  let proyecto = "";
  let tarea = "";
  const p1 = m.match(
    /proyecto\s+["']?([^"'\n]+?)(?=\s+tarea\b|\s+[:,]|\s+con\s+|\s+para\s+|$)/i,
  );
  if (p1) proyecto = p1[1].trim();
  const t1 = m.match(
    /tarea\s+["']?([^"'\n]+?)(?=\s+(?:\d|h\b|con|y|materi|torni|proyecto|descripcion|desc|km)|$)/i,
  );
  if (t1) tarea = t1[1].trim();
  if (!proyecto) {
    const p2 = m.match(
      /(?:en|del|en el)\s+proyecto\s+["']?([a-z0-9áéíóúñ][^,\n.]{1,50})/i,
    );
    if (p2) proyecto = p2[1].trim();
  }
  if (!tarea) {
    const t2 = m.match(
      /(?:en la|a la|la)\s+tarea\s+["']?([a-z0-9áéíóúñ][^,\n.]{1,50})/i,
    );
    if (t2) tarea = t2[1].trim();
  }
  return { proyecto, tarea };
}

function parseProductosLinea(m) {
  const out = [];
  const stopW = (s) => /^(horas?|h|proyecto|tarea|trabaj|dedic|imput|registr|parte|stock)$/i.test(s.trim());
  const chunk = m.replace(/y\s+(\d)/g, ", $1");
  const parts = chunk.split(/,|\s+y\s+(?=\d)/);
  for (const seg of parts) {
    const r = seg.match(
      /(\d+[\.,]?\d*)\s*(?:x|×|uds?)?\s*([a-z0-9áéíóúñ.\- ]{2,40})/i,
    );
    if (r) {
      const q = parseFloat(r[1].replace(",", "."));
      let nombre = (r[2] || "").replace(/\s+/g, " ").trim();
      if (nombre && !stopW(nombre) && q > 0 && q < 1e6)
        out.push({ nombre, cantidad: q });
    }
  }
  return out.slice(0, 30);
}

function hasMaterialIntent(m) {
  if (/(materi|torni|cable|stock|producto|consumi|repon|unidad|uds|bulto|kilo|litro|metro|tornill|junt|pieza|ud\.)/.test(m))
    return true;
  return parseProductosLinea(m).length > 0;
}

function isPresupuestoOEstim(m) {
  return /(presupuest|hara\s+falta|vamos\s+a\s+necesitar|necesitare?mos|estim|aprox|diagnost|para presupuest)/.test(
    m,
  );
}

// ----- Reglas: cubrir acciones alineadas con el Switch + registrar_horas (pre-Router) ----

/** @type {Array<{ id: string, prior: number, when: (a: string, b: string) => boolean, go: (a: string, b: string) => Record<string, unknown> }>} */
const REGLAS = [
  {
    id: "envio_masivo",
    prior: 100,
    when: (m, o) => /^env[ií]o\s+masivos?\s*:/i.test(o),
    go: (m, o) => {
      const mm = o.replace(/^env[ií]o\s+masivos?\s*:/i, "").trim();
      return {
        accion: "envio_masivos",
        mensaje_masivo: mm || "(vacio)",
        respuesta_usuario: "Enviando mensaje masivo…",
      };
    },
  },
  {
    id: "bienvenida",
    prior: 98,
    when: (m) =>
      nPalabras <= 18 &&
      /(quien\s+eres|que\s+eres|hola[,]?\s*(quien|que)\s+eres)/.test(m),
    go: () => ({
      accion: "mensaje_bienvenida",
      respuesta_usuario:
        "Soy tu asistente de Odoo. Puedo con partes, horas, fichajes, compras, consultas. Dime que necesitas.",
    }),
  },
  {
    id: "lopd",
    prior: 96,
    when: (m) => /(\blopd\b|firmar.*lopd|firma\s+lopd)/.test(m) && nPalabras < 30,
    go: () => ({ accion: "firmar_lopd", respuesta_usuario: "Consultando tareas para LOPD…" }),
  },
  {
    id: "parte_y_stock",
    prior: 94,
    when: (m) => {
      if (nPalabras > 120) return false;
      if (
        /(cuantas|cuanto|consulta|dime|resumen|ventas?|facturas?)\b.*(horas|dedic|proyecto)/.test(m) &&
        !/registr|imputa|anota|parte|material|materi|torni|stock/.test(m)
      )
        return false;
      const hPart = firstHours(m);
      const mat = hasMaterialIntent(m);
      const pres = isPresupuestoOEstim(m);
      if (!mat && !pres) return false;
      return !!(hPart || /(registr\w*|imput\w*|anot\w*|\bparte\b|stock|consumo|reponer|materi)/.test(m));
    },
    go: (m) => {
      const hp = firstHours(m);
      let horas = hp && hp.v > 0 ? hp.v : 0;
      if (!horas) {
        const g = m.match(/(\d+[\.,]?\d*)\s*h(oras?)?/);
        if (g) horas = parseFloat(g[1].replace(",", ".")) || 0;
      }
      const hpres = horasPresupuestadas(m) || 0;
      const diag = isPresupuestoOEstim(m) || (hpres > 0 && /diagnost|presupuest|necesit|estim|aprox/.test(m));
      const { proyecto, tarea } = parseProyectoTarea(m);
      const productos = parseProductosLinea(m);
      const dTexto = orig.slice(0, 500) || m.slice(0, 500);
      return {
        accion: "registrar_parte_y_stock",
        is_diagnosis_task: !!diag,
        diagnostico_detectado: !!diag,
        horas: diag && horas === 0 && hpres > 0 ? 0 : horas,
        horas_presupuestadas: hpres,
        proyecto: proyecto || PROYECTO_DEFAULT,
        tarea: tarea || "Trabajo de campo",
        descripcion: dTexto,
        productos: productos.length
          ? productos
          : hasMaterialIntent(m)
            ? []
            : [],
        tipo_accion_stock: /(consumi|gast|resta|descuent)/.test(m) ? "consumir" : undefined,
        cliente: "interno",
        respuesta_usuario:
          "Voy a preparar el parte (horas y/o materiales) con lo detectado. Comprueba o confirma en el siguiente paso.",
      };
    },
  },
  {
    id: "registrar_horas",
    prior: 80,
    when: (m) => {
      if (nPalabras > 80) return false;
      if (isPresupuestoOEstim(m) || hasMaterialIntent(m)) return false;
      if (!/(\d+[\.,]?\d*)\s*h(oras?)?|una|dos|tres|cuatro|cinco|seis|siete|ocho|nueve|diez|media|cuarto.*horas?/.test(m)) return false;
      if (!/(registr\w*|imput\w*|anot\w*|\bhoras?\b|parte(?!.+(material|stock|torni)))/.test(m)) return false;
      if (!/(proyecto|tarea)/.test(m)) return false;
      const h = firstHours(m) || m.match(/(\d+[\.,]?\d*)\s*h/);
      if (!h) return false;
      return true;
    },
    go: (m) => {
      const hp = firstHours(m);
      let horas = hp && hp.v > 0 ? hp.v : 0;
      if (!horas) {
        const g = m.match(/(\d+[\.,]?\d*)\s*h(oras?)?\b/);
        if (g) horas = parseFloat(g[1].replace(",", ".")) || 0;
      }
      const { proyecto, tarea } = parseProyectoTarea(m);
      return {
        accion: "registrar_horas",
        proyecto: proyecto || PROYECTO_DEFAULT,
        tarea: tarea || "Tarea",
        horas: horas || 0,
        descripcion: orig.slice(0, 400) || "Trabajo registrado",
        respuesta_usuario: `Registro de ${horas} h (proyecto/tarea detectados)…`,
      };
    },
  },
  {
    id: "compra_inventario",
    prior: 78,
    when: (m) =>
      nPalabras < 55 &&
      /(he\s+comprado|compr[eé]\s|compra\s+de|registrar\s+compra|nuevo\s+inventario|me\s+han\s+llegado|orden\s+de\s+compra)/.test(
        m,
      ) &&
      /\d/.test(m) &&
      !/presupuest\s+venta|ventas?\s+pedid/.test(m),
    go: (m) => ({
      accion: "registrar_compra_inventario",
      respuesta_usuario: "Procesando compra / inventario…",
    }),
  },
  {
    id: "fichaje_gps",
    prior: 90,
    when: (m, o) => {
      const c = o.match(/(-?\d{1,3}(?:\.\d+)?)\s*[,;\s]+\s*(-?\d{1,3}(?:\.\d+)?)/);
      if (!c) return false;
      const la = parseFloat(c[1]);
      const lo = parseFloat(c[2]);
      if (!Number.isFinite(la) || !Number.isFinite(lo) || Math.abs(la) > 90 || Math.abs(lo) > 180) return false;
      return /(fichaje|fichar|entrada|salida|check\s*in|check\s*out)/.test(m) && nPalabras < 60;
    },
    go: (m, o) => {
      const c = o.match(/(-?\d{1,3}(?:\.\d+)?)\s*[,;\s]+\s*(-?\d{1,3}(?:\.\d+)?)/);
      const la = parseFloat(c[1]);
      const lo = parseFloat(c[2]);
      let tf = "auto";
      if (/\bentrada\b/.test(m)) tf = "entrada";
      else if (/\bsalida\b/.test(m)) tf = "salida";
      return {
        accion: "registrar_fichaje",
        tipo_fichaje: tf,
        latitude: la,
        longitude: lo,
        respuesta_usuario: "Registrando fichaje…",
      };
    },
  },
  {
    id: "gasto",
    prior: 76,
