  }))
  .filter((p) => p.nombre);

// ✅ Y DESPUÉS metes la línea de presupuesto si aplica
if (isDiagnosis && horasPresup > 0) {
  items.push({
    nombre: 'Horas presupuestadas',
    cantidad: horasPresup,
    product_id: false,
    notes: 'Estimación / Presupuesto (diagnóstico/presupuesto)',
  });
}

console.log('📦 Productos normalizados:', items);

// Proyecto FSM por defecto
const proyecto = asStr(x.proyecto) || 'Servicio de campo';
const tareaSugerida =
  asStr(x.tarea) || `Intervención - ${new Date().toLocaleDateString('es-ES')}`;

const uid = x.uid || ($('Autenticar Odoo')?.item?.json?.result);
const db = x.db || 'mchecaazor-webinar3-main-30740598';

const odoo_user = asStr(x.odoo_user || x.cliente_perfil?.email || '');
const odoo_user_id = x.odoo_user_id || x.cliente_perfil?.user_id || null;

const transcripcion_original = asStr(
  x.transcripcion_original || x.mensaje_usuario_original || x.mensaje_original || ''
);
const mensaje_usuario_original = asStr(x.mensaje_usuario_original || x.mensaje_original || '');

const contextoKey = `memoria_${chatId}`;
let memoria = global[contextoKey] || {};

const parteEnMemoria = {
