};

// REGISTRAR MATERIALES (robusto en esta rama)
// - timesheet_line_id SIEMPRE se lee de "HTTP Registrar Horas Directo FSM"
// - productos se leen con prioridad: input validados > Validar Productos1 validados > input productos/datos_parte > seed Registrar Tarea Odoo > pendientes > reg > normalizar
// ✅ CORRECCION: las "horas_presupuestadas" NO son materiales (no deben entrar en account.analytic.line.product)

const firstJson = (nodeName) => {
  try { return $items(nodeName, 0)?.[0]?.json ?? null; } catch { return null; }
};

const parseMaybeJson = (v) => {
  if (!v) return null;
  if (typeof v === 'object') return v;
  if (typeof v === 'string') {
    try { return JSON.parse(v); } catch { return null; }
  }
  return null;
};

// ✅ 1) timesheet_line_id (robusto para rama normal + corrección productos)
// Prioridad: input -> Registro (Registrar Horas Directo FSM) -> memoria -> HTTP

const toNum = (v) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
};

const httpHoras = firstJson('HTTP Registrar Horas Directo FSM') || {};
const regNodeWrap = firstJson('Registrar Horas Directo FSM') || {};
const reg = regNodeWrap.registro || regNodeWrap || {};

const memRow = firstJson('Preparar Datos AI Agent') || {};
const pendientesMem = parseMaybeJson(memRow?.datos_pendientes) || {};

let timesheetLineId =
  toNum($json.timesheet_line_id) ||
  toNum(reg.timesheet_line_id) ||
  toNum(pendientesMem.timesheet_line_id) ||
  (() => {
    let raw =
      httpHoras.result ??
      httpHoras.body?.result ??
      httpHoras.json?.result ??
      null;
    if (Array.isArray(raw)) raw = raw[0];
    return toNum(raw);
  })();

if (!timesheetLineId || timesheetLineId <= 0) {
  return {
    skip_materiales: true,
    motivo: 'Sin timesheet_line_id (input/registro/memoria/HTTP)',
    timesheet_line_id: timesheetLineId || null,
    debug_timesheet_sources: {
      input: $json.timesheet_line_id ?? null,
      reg: reg.timesheet_line_id ?? null,
      mem: pendientesMem.timesheet_line_id ?? null,
      http_has_item: !!firstJson('HTTP Registrar Horas Directo FSM'),
    },
  };
}


// ✅ 2) contexto

const norm = firstJson('Normalizar Parte+Materiales FSM') || {};
const auth = firstJson('Autenticar Odoo') || {};

// ⚠️ validador (según ramas)
const valid =
  firstJson('Validar Productos1') ||
  firstJson('Validar Productos FSM') ||
  {};

// ✅ seed del nodo Registrar Tarea Odoo (donde a menudo está el producto correcto estructurado)
const seed = firstJson('Registrar Tarea Odoo') || {};
const seedParte = seed.datos_parte || {};

// memoria postgres (si existe)
const dpObj =
  parseMaybeJson($json.datos_pendientes) ||
  parseMaybeJson($json.datos_pendientes_json) ||
  $json.datos_pendientes ||
  null;

// ✅ 3) productos (PRIORIDAD CORREGIDA)
let productos = [];

// 0) input actual ya trae validados (p.ej. vienes de la corrección/validación)
if (Array.isArray($json.productos_validados) && $json.productos_validados.length) {
  productos = $json.productos_validados;

// ✅ 0.1) lo que dejó "Validar Productos1" (VALORES YA CON product_id) → PRIORIDAD MUY ALTA
} else if (Array.isArray(valid.productos_validados) && valid.productos_validados.length) {
  productos = valid.productos_validados;

// 0.2) input actual trae productos ya estructurados (corrección parseada)
} else if (Array.isArray($json.productos) && $json.productos.length) {
  productos = $json.productos;

// 0.3) o dentro del input datos_parte
} else if (Array.isArray($json.datos_parte?.productos) && $json.datos_parte.productos.length) {
  productos = $json.datos_parte.productos;

// 0.4) seed de “Registrar Tarea Odoo”
} else if (Array.isArray(seedParte.productos) && seedParte.productos.length) {
  productos = seedParte.productos;

// 0.5) datos_pendientes.datos_parte.productos
} else if (Array.isArray(dpObj?.datos_parte?.productos) && dpObj.datos_parte.productos.length) {
  productos = dpObj.datos_parte.productos;

// 0.6) fallback registro original (a veces viene “mal escrito” aquí)
} else if (Array.isArray(reg.productos) && reg.productos.length) {
  productos = reg.productos;

// 0.7) fallback normalizado
} else if (Array.isArray(norm.productos) && norm.productos.length) {
  productos = norm.productos;
}

// ✅ 3b) FILTRAR: quitar "Horas presupuestadas" (no son materiales)
const normText = (s) =>
  String(s ?? '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\s+/g, ' ')
    .trim();

const isPresupuestoItem = (p) => {
  const name = normText(p?.product_name || p?.nombre || p?.notes || '');
  const notes = normText(p?.notes || '');

  const byName =
    name.includes('hora presupuestada') ||
    name.includes('horas presupuestadas') ||
    name === 'horas' ||
    name.includes('presupuesto') ||
    name.includes('estimacion') ||
    name.includes('estimación');

  const byNotes =
    notes.includes('presupuesto') ||
    notes.includes('estimacion') ||
    notes.includes('estimación');

  const pid = p?.product_id;
  const pidNum = Array.isArray(pid) ? Number(pid[0]) : Number(pid);
  const noPid = !Number.isFinite(pidNum) || pidNum <= 0;

  return (
    byName ||
    byNotes ||
    (noPid && name.includes('horas') && (name.includes('presup') || name.includes('estim')))
  );
};

if (Array.isArray(productos) && productos.length) {
  productos = productos.filter((p) => !isPresupuestoItem(p));
}

if (!Array.isArray(productos) || productos.length === 0) {
  return {
    skip_materiales: true,
    motivo: 'Sin materiales (solo venían horas presupuestadas / estimación, que NO se registran como consumo)',
    timesheet_line_id: timesheetLineId,
    debug: {
      input_pv_len: Array.isArray($json.productos_validados) ? $json.productos_validados.length : null,
      valid_pv_len: Array.isArray(valid.productos_validados) ? valid.productos_validados.length : null,
      input_prod_len: Array.isArray($json.productos) ? $json.productos.length : null,
      input_dp_prod_len: Array.isArray($json.datos_parte?.productos) ? $json.datos_parte.productos.length : null,
      seed_prod_len: Array.isArray(seedParte.productos) ? seedParte.productos.length : null,
      dp_seed_prod_len: Array.isArray(dpObj?.datos_parte?.productos) ? dpObj.datos_parte.productos.length : null,
      reg_len: Array.isArray(reg.productos) ? reg.productos.length : null,
      norm_len: Array.isArray(norm.productos) ? norm.productos.length : null,
      horas_presupuestadas: reg.horas_presupuestadas ?? $json.horas_presupuestadas ?? null,
      reg_wrap_has_registro: !!regNodeWrap?.registro,
      reg_wrap_keys: regNodeWrap ? Object.keys(regNodeWrap) : null,
    },
  };
}

// ✅ 4) separar conId vs sinId
const conId = [];
const sinId = [];

for (const p of productos) {
  const name = String(p.product_name || p.nombre || p.notes || '').trim();
  const qty = Number(p.quantity || p.cantidad || 1);

  let pid = p.product_id;
  if (Array.isArray(pid)) pid = pid[0];
  if (pid === false || pid === null || pid === undefined || pid === '') pid = null;
  else pid = Number(pid);

  const uom =
    (Array.isArray(p.uom_id) ? p.uom_id[0] : p.uom_id) ||
    (Array.isArray(p.product_uom_id) ? p.product_uom_id[0] : p.product_uom_id) ||
    null;

  const item = {
    timesheet_line_id: timesheetLineId,
    product_id: pid,
    quantity: Number.isFinite(qty) && qty > 0 ? qty : 1,
    notes: name,
  };

  if (uom) item.product_uom_id = Number(uom);

  if (Number.isFinite(pid) && pid > 0) conId.push(item);
  else if (name) sinId.push({ nombre: name, cantidad: item.quantity });
}

if (conId.length === 0 && sinId.length === 0) {
  return {
    skip_materiales: true,
    motivo: 'Materiales vacíos o sin nombre (tras filtrar horas presupuestadas)',
    timesheet_line_id: timesheetLineId,
  };
}

// ✅ 5) db/uid
const db =
  reg.db ||
  norm.db ||
  valid.db ||
  $json.db ||
  seed.db ||
  'mchecaazor-webinar3-main-30740598';

const uid =
  reg.uid ||
  norm.uid ||
  valid.uid ||
  $json.uid ||
  seed.uid ||
  auth.result ||
  2;

const pass = 'admin';

// ✅ 6) si faltan IDs -> pedir resolución por búsqueda
if (sinId.length > 0 && conId.length === 0) {
  const names = sinId.map((x) => x.nombre).filter(Boolean);

  let domain = [];
  if (names.length === 1) {
    domain = [['name', 'ilike', names[0]]];
  } else {
    for (let i = 0; i < names.length; i++) {
      if (i < names.length - 1) domain.push('|');
      domain.push(['name', 'ilike', names[i]]);
    }
  }

  const payloadBuscarProductos = {
    jsonrpc: '2.0',
    method: 'call',
    params: {
      service: 'object',
      method: 'execute_kw',
      args: [
        db, Number(uid), pass,
        'product.product', 'search_read',
        [domain],
        { fields: ['id', 'name', 'display_name', 'uom_id', 'default_code'], limit: 80 },
      ],
    },
    id: Math.floor(Math.random() * 1e6),
  };

  return {
    skip_materiales: true,
    motivo: 'Hay materiales pero sin product_id. Hay que resolverlos por nombre antes de registrar consumo.',
    timesheet_line_id: timesheetLineId,
    productos_sin_id: sinId,
    necesita_resolver_productos: true,
    payload_buscar_productos: payloadBuscarProductos,
    db,
    uid: Number(uid),
  };
}

// ✅ 7) si hay IDs -> crear líneas de consumo en el parte (account.analytic.line.product)
if (conId.length > 0) {
  const payloadCreate = {
    jsonrpc: '2.0',
    method: 'call',
    params: {
      service: 'object',
      method: 'execute_kw',
      args: [
        db,
        Number(uid),
        pass,
        'account.analytic.line.product',
        'create',
        [conId],
      ],
