    id: Math.floor(Math.random() * 1e6),
  };

  return {
    skip_materiales: false,
    payload: payloadCreate,
    timesheet_line_id: timesheetLineId,
    productos_creados: conId.length,
    productos_sin_id: sinId,
    db,
    uid: Number(uid),
  };
}

// fallback final
return {
  skip_materiales: true,
  motivo: 'No hay materiales registrables',
  timesheet_line_id: timesheetLineId,
  debug_paths: {
    input_productos_validados: Array.isArray($json.productos_validados) ? $json.productos_validados.length : null,
    valid_productos_validados: Array.isArray(valid.productos_validados) ? valid.productos_validados.length : null,
    input_productos: Array.isArray($json.productos) ? $json.productos.length : null,
    input_datos_parte_productos: Array.isArray($json.datos_parte?.productos) ? $json.datos_parte.productos.length : null,
    seed_productos: Array.isArray(seedParte.productos) ? seedParte.productos.length : null,
    dp_productos: Array.isArray(dpObj?.datos_parte?.productos) ? dpObj.datos_parte.productos.length : null,
    reg_len: Array.isArray(reg.productos) ? reg.productos.length : null,
    norm_len: Array.isArray(norm.productos) ? norm.productos.length : null,
  },
};

// ✅ Registrar Horas Directo FSM
// ✅ FIXES:
// 1) Idempotencia: si ya existe timesheet_line_id (input o memoria), NO vuelve a crear horas
// 2) Transcripción: MENSAJE INICIAL siempre el inicial; MENSAJE HORAS solo si texto tiene número válido
// 3) Evita que "sí" o "juntas" contaminen los mensajes
// 4) En corrección de productos, reutiliza transcripción guardada en memoria (no recalcula)

const safeNodeJson = (name) => {
  try { return $items(name, 0)?.[0]?.json ?? null; } catch { return null; }
};

const parseJSONSafe = (v) => {
  try { return typeof v === 'string' ? JSON.parse(v) : (v || {}); } catch { return {}; }
};

const toNum = (v) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
};

const clean = (s) => String(s ?? '').trim();

const x = $json || {};

// -------------------------
// ✅ Contexto base
// -------------------------
const seed = safeNodeJson('Registrar Tarea Odoo') || {};
const seedReg = seed.datos_registrados || {};

const memRow = safeNodeJson('Preparar Datos AI Agent') || {};
const pendientes = parseJSONSafe(memRow?.datos_pendientes);

const normalizado = safeNodeJson('Normalizar Parte+Materiales FSM') || {};
const authNode = safeNodeJson('Autenticar Odoo') || {};
const prepCompleto = safeNodeJson('FSM ▸ Preparar Datos Completos') || {};
const prepUser = safeNodeJson('Preparar Buscar Usuario Odoo') || {};

// -------------------------
// ✅ Flags de rama
// -------------------------
const enCorreccionProductos =
  memRow?.esperando_confirmacion === 'correccion_productos' ||
  x.necesita_resolver_productos === true ||
  (Array.isArray(x.productos_sin_id) && x.productos_sin_id.length > 0) ||
  !!x.payload_buscar_productos;

// -------------------------
// ✅ Idempotencia: detectar si YA existe línea creada
// -------------------------
const existingTimesheetLineId = toNum(
  x.timesheet_line_id ||
  x.timesheetLineId ||
  x.timesheet_line_id_creado ||
  pendientes.timesheet_line_id ||
  pendientes.timesheetLineId
);

// ⚠️ Si ya hay timesheet_line_id, NO volvemos a crear horas
if (existingTimesheetLineId && existingTimesheetLineId > 0) {
  return {
    payload: null,
    skip_registrar_horas: true,
    motivo: enCorreccionProductos
      ? 'Reentrada por corrección de productos: NO se vuelven a registrar horas'
      : 'Ya existía timesheet_line_id: NO se vuelven a registrar horas',
    timesheet_line_id: existingTimesheetLineId,
    ...x,
    registro: {
      ...(x.registro || {}),
      chat_id: x.chat_id || pendientes.chat_id || memRow.chat_id || seed.chat_id || normalizado.chat_id,
      db: x.db || pendientes.db || seed.db || normalizado.db || 'mchecaazor-webinar3-main-30740598',
      uid: toNum(x.uid || pendientes.uid || seed.uid || normalizado.uid || authNode?.result) || 2,
      timesheet_line_id: existingTimesheetLineId,
    },
  };
}

// -------------------------
// ✅ IDs tarea/proyecto
// -------------------------
const tareaId = toNum(
  x.tarea_id ||
  x.task_id ||
  x.datos_registrados?.task_id ||
  pendientes.tarea_id ||
  seedReg.task_id
);

const proyectoId = toNum(
  x.proyecto_id ||
  x.project_id ||
  x.datos_registrados?.project_id ||
  pendientes.proyecto_id ||
  seedReg.project_id
);

const tareaNombre =
  x.tarea ||
  x.tarea_nombre ||
  pendientes.tarea_nombre ||
  seed.tarea ||
  'Tarea';

const proyectoNombre =
  x.proyecto_nombre ||
  pendientes.proyecto_nombre ||
  seed.proyecto_nombre ||
  'Proyecto';

const datosParte = x.datos_parte || pendientes.datos_parte || {};

// -------------------------
// ✅ descripcion y productos
// -------------------------
const descripcion =
  x.descripcion ||
  x.datos_parte?.descripcion ||
  datosParte?.descripcion ||
  pendientes?.datos_parte?.descripcion ||
  seedReg?.name ||
  '';

const productos =
  x.productos ||
  x.datos_parte?.productos ||
  datosParte?.productos ||
  pendientes?.datos_parte?.productos ||
  [];

// -------------------------
// ✅ HORAS (solo crear si hay >0)
// -------------------------
let horas = null;
const horasCandidatos = [
  x.horas,
  x.unit_amount,
  x.datos_registrados?.unit_amount,
  x.datos_parte?.horas,
  datosParte.horas,
  pendientes.datos_parte?.horas,
  seedReg.unit_amount,
];

for (const candidate of horasCandidatos) {
  const num = toNum(candidate);
  if (num !== null && num > 0) {
    horas = num;
    break;
  }
}

horas = horas ?? 0;

if (horas <= 0) {
  const debugInfo = {
    'x.horas': x.horas,
    'x.unit_amount': x.unit_amount,
    'x.datos_registrados?.unit_amount': x.datos_registrados?.unit_amount,
    'x.datos_parte?.horas': x.datos_parte?.horas,
    'datosParte.horas': datosParte.horas,
    'pendientes.datos_parte?.horas': pendientes.datos_parte?.horas,
    'seedReg.unit_amount': seedReg.unit_amount,
    'horas_final': horas,
  };
  throw new Error(`Horas inválidas: ${horas}. DEBUG: ${JSON.stringify(debugInfo, null, 2)}`);
}

// -------------------------
// ✅ Credenciales
// -------------------------
const DB =
  x.db ||
  pendientes.db ||
  seed.db ||
  normalizado.db ||
  'mchecaazor-webinar3-main-30740598';

const UID =
  toNum(x.uid_admin || x.uid || pendientes.uid_admin || seed.uid || normalizado.uid) ||
  toNum(authNode?.result) ||
  2;

const PASS =
  x.pass_admin ||
  x.pass ||
  pendientes.pass_admin ||
  'admin';

const hoy = new Date().toISOString().split('T')[0];

// -------------------------
// ✅ user_id desde "Buscar Usuario Odoo"
// -------------------------
let userIdFromPerfil = null;
let userNameFromPerfil = null;

try {
  const listaUsuarios =
    x?.result ??
    x?.body?.result ??
    x?.data?.result ??
    x?.json?.result ??
    [];

  const usuario = Array.isArray(listaUsuarios) && listaUsuarios.length ? listaUsuarios[0] : null;
  userIdFromPerfil = usuario?.id ?? null;
  userNameFromPerfil = usuario?.name ?? null;
} catch {}

// -------------------------
// ✅ Diagnóstico
// -------------------------
const esDiagnosis =
  x.is_diagnosis_task === true ||
  datosParte.is_diagnosis_task === true ||
  pendientes.is_diagnosis_task === true ||
  false;

// -------------------------
// ✅ TRANSCRIPCIÓN (NO contaminada + no recalcular en corrección)
// -------------------------
let transcripcionCompleta = '';

if (enCorreccionProductos) {
  // ✅ En corrección: usa lo guardado (no lo machaques con "juntas"/"si")
  transcripcionCompleta =
    clean(pendientes?.transcripcion_real) ||
    clean(pendientes?.transcripcion_original) ||
    clean(descripcion) ||
    'Sin transcripción disponible';
} else {
  // ✅ MENSAJE INICIAL: SOLO de fuentes iniciales estables
  const primerMensaje =
    pendientes?.datos_parte?.mensaje_usuario_original ||
    pendientes?.datos_parte?.transcripcion_original ||
    seed?.mensaje_usuario_original ||
    seed?.transcripcion_original ||
    null;

  const mensajeActualRaw =
    memRow?.mensaje_usuario ||
    x.mensaje_usuario ||
    prepCompleto?.message?.text ||
    prepUser?.message?.text ||
    normalizado?.message?.text ||
    x.message?.text ||
    x.body?.message?.text ||
    x.text ||
    null;

  const parseHorasFromText = (txt) => {
    const s = clean(txt).toLowerCase();
    if (!s) return null;

    const banal = new Set(['si', 'sí', 'ok', 'vale', 'de acuerdo', 'correcto']);
    if (banal.has(s)) return null;

    const m = s.replace(',', '.').match(/(\d+(\.\d+)?)/);
    if (!m) return null;

    const n = Number(m[1]);
    return Number.isFinite(n) && n > 0 ? n : null;
  };

  const p = clean(primerMensaje);
  const horasEnTexto = parseHorasFromText(mensajeActualRaw);
  const mensajeHoras = (horasEnTexto !== null) ? clean(mensajeActualRaw) : null;

  if (p && mensajeHoras) {
    transcripcionCompleta = (p === mensajeHoras)
      ? p
      : `🟦 MENSAJE INICIAL:\n${p}\n\n🟩 MENSAJE HORAS:\n${mensajeHoras}`;
  } else if (p) {
    transcripcionCompleta = p; // ✅ si no hay mensaje horas válido, solo inicial
  } else if (mensajeHoras) {
    transcripcionCompleta = mensajeHoras;
  } else {
    transcripcionCompleta = clean(descripcion) || 'Sin transcripción disponible';
  }
}

const transcripcionReal = transcripcionCompleta;

// -------------------------
// ✅ Horas presupuestadas
// -------------------------
const horasPresupuestadas =
  toNum(
    x.horas_presupuestadas ||
    datosParte.horas_presupuestadas ||
    pendientes.horas_presupuestadas ||
    seed.horas_presupuestadas ||
    normalizado?.horas_presupuestadas ||
    0
  ) ?? 0;

// -------------------------

// -------------------------
// ✅ Travel fields (distancia y tiempo de desplazamiento)
// -------------------------
const travel_distance_km = toNum(
  x.travel_distance_km ||
  datosParte.travel_distance_km ||
  pendientes?.datos_parte?.travel_distance_km ||
  pendientes?.travel_distance_km ||
  seed.travel_distance_km ||
  normalizado?.travel_distance_km ||
  0
) ?? 0;

const travel_time_hours = toNum(
  x.travel_time_hours ||
  datosParte.travel_time_hours ||
  pendientes?.datos_parte?.travel_time_hours ||
  pendientes?.travel_time_hours ||
  seed.travel_time_hours ||
  normalizado?.travel_time_hours ||
  0
) ?? 0;

console.log('🚗 Travel distance_km:', travel_distance_km);
console.log('⏱️ Travel time_hours:', travel_time_hours);

// ✅ Descripción mejorada
// -------------------------
let descripcionMejorada = (descripcion || seedReg.name || `Parte - ${tareaNombre}`).trim();

if (esDiagnosis && horasPresupuestadas > 0) {
  descripcionMejorada = `${descripcionMejorada} [PRESUPUESTO: ${horasPresupuestadas}h]`;
}

if (Array.isArray(productos) && productos.length > 0) {
  const listaProductos = productos
    .map(p => `- ${p.nombre || p.product_name || 'Producto sin nombre'}: ${p.cantidad || p.quantity || 1} unidad(es)`)
    .join('\n');

  if (esDiagnosis) {
    descripcionMejorada = `${descripcionMejorada}\n\n📋 PRODUCTOS MENCIONADOS (Presupuesto):\n${listaProductos}`;
  } else {
    descripcionMejorada = `${descripcionMejorada}\n\n📦 MATERIALES UTILIZADOS:\n${listaProductos}`;
  }
}

if (transcripcionCompleta) {
  descripcionMejorada = `${descripcionMejorada}\n\n🗒️ CONTEXTO COMPLETO (OPERARIO):\n${transcripcionCompleta}`;
}

// -------------------------
// ✅ Validación IDs
// -------------------------
if (!tareaId || !proyectoId) {
  throw new Error(
    `Faltan IDs. task_id=${tareaId} project_id=${proyectoId}. ` +
    `Revisa que lleguen desde Registrar Tarea Odoo / pendientes / input.`
  );
}

// -------------------------
// ✅ Payload create (account.analytic.line)
// -------------------------
const valoresParte = {
  name: descripcionMejorada,
  project_id: proyectoId,
  task_id: tareaId,
  unit_amount: horas,
  date: hoy,
  transcripcion_real: transcripcionReal,
  is_diagnosis_task: esDiagnosis,
  travel_distance_km: travel_distance_km,
  travel_time_hours: travel_time_hours,
  ...(userIdFromPerfil ? { user_id: Number(userIdFromPerfil) } : {}),
};

const payload = {
  jsonrpc: '2.0',
  method: 'call',
  params: {
    service: 'object',
    method: 'execute_kw',
    args: [
      DB, UID, PASS,
      'account.analytic.line', 'create',
      [[valoresParte]],
    ],
  },
  id: Math.floor(Math.random() * 1e6),
};

return {
  payload,
  skip_registrar_horas: false,
  registro: {
    chat_id: x.chat_id || seed.chat_id || normalizado.chat_id || memRow?.chat_id,
    proyecto: proyectoNombre,
    tarea: tareaNombre,
    horas,
    horas_presupuestadas: horasPresupuestadas,
    is_diagnosis_task: esDiagnosis,
    descripcion: (descripcion || seedReg.name || `Parte - ${tareaNombre}`).trim(),
    transcripcion_original: transcripcionCompleta,
    transcripcion_real: transcripcionReal,
    task_id: tareaId,
    project_id: proyectoId,
    travel_distance_km: travel_distance_km,
    travel_time_hours: travel_time_hours,
    odoo_user: x.odoo_user || pendientes.odoo_user || seed.odoo_user || normalizado.odoo_user || memRow?.odoo_user || null,
    odoo_user_id: userIdFromPerfil || null,
    odoo_user_name: userNameFromPerfil || null,
    productos,
    db: DB,
    uid: UID,
  },
};

// ✅ Preparar Buscar Usuario Odoo (robusto para rama registrar_tarea)

const x = $json;

// helper: leer json de otro nodo si existe / se ejecutó
const safeNodeJson = (name) => {
  try {
    const it = $items(name, 0);
    return it?.[0]?.json ?? null;
  } catch {
    return null;
  }
};

// 1) Fuentes posibles
const normalizado = safeNodeJson('Normalizar Parte+Materiales FSM') || null;
const authNode = safeNodeJson('Autenticar Odoo') || null;

const memRow = safeNodeJson('Preparar Datos AI Agent') || null;

// 2) Parse seguro de datos_pendientes de Postgres
const parseJSONSafe = (v) => {
  try { return typeof v === 'string' ? JSON.parse(v) : (v || {}); }
  catch { return {}; }
};

const pendientes = parseJSONSafe(memRow?.datos_pendientes);

// 3) Credenciales / contexto (prioridad: input -> pendientes -> normalizado -> defaults)
const DB =
  x.db ||
  pendientes.db ||
  normalizado?.db ||
  'mchecaazor-webinar3-main-30740598';

let UID =
  x.uid_admin ||
  x.uid ||
  pendientes.uid_admin ||
  normalizado?.uid ||
  2;

// si existe Autenticar Odoo y trae result, úsalo
if (authNode?.result) UID = authNode.result;

const PASS =
  x.pass_admin ||
  pendientes.pass_admin ||
  'admin';

// 4) Email del usuario final (muy importante)
const email =
  x.odoo_user ||
  pendientes.odoo_user ||
  normalizado?.odoo_user ||
  memRow?.odoo_user ||
  '';

// Si no hay email, NO rompas el flujo: devuelve skip para que lo bypasses
if (!email) {
  return {
    ...x,
    db: DB,
    uid: UID,
    pass_admin: PASS,
    skip_user_lookup: true,
    motivo: 'Falta odoo_user/email para buscar res.users',
  };
}

// 5) Payload JSON-RPC
const payload = {
  jsonrpc: '2.0',
  method: 'call',
  params: {
    service: 'object',
    method: 'execute_kw',
    args: [
      DB, UID, PASS,
      'res.users', 'search_read',
      [[
        '|',
        ['login', '=', email],
        ['email', '=', email],
      ]],
      { fields: ['id', 'name', 'login', 'email', 'partner_id'], limit: 1 },
    ],
  },
  id: Math.floor(Math.random() * 1e6),
};

return {
  ...x,
  db: DB,
  uid: UID,
  pass_admin: PASS,
  odoo_user: email,
  payload,
};

// Log para datos inválidos que no se pueden guardar en PostgreSQL
console.log('❌ DATOS INVÁLIDOS - No se guardó en PostgreSQL:');
console.log('📄 Datos recibidos:', JSON.stringify($json, null, 2));
console.log('🚫 Razón:', $json.razon || 'No especificada');
console.log('📊 Chat ID original:', $json.chat_id_original);
console.log('🔢 Chat ID numérico:', $json.chat_id_numerico);

return { 
  mensaje: 'Datos no guardados en PostgreSQL por ser inválidos',
