// PREPARAR CONSULTA ESTADO PROYECTO (con filtro por ETAPA)
let base = $json || {};
try { base = $('Router de Acciones FIXED').first().json || base; } catch {}
try { base = Object.assign({}, base, $('Preparar Datos AI Agent').first().json || {}); } catch {}

const rawMsg = String(base.mensaje_usuario || base.mensaje_original || '').trim();

// --- detectar etapa solicitada ---
const stages = [
  { key: 'in_progress', re: /(en\s+(proceso|progreso|curso)|in\s*progress|andando)/i,
    labels: ['In Progress','En Progreso','En proceso','En curso'] },
  { key: 'new', re: /(nuevo(s)?|nueva(s)?|por\s*empezar|planificaci[oó]n|por\s*hacer|to\s*do)/i,
    labels: ['New','Nuevo','Por hacer','To Do'] },
  { key: 'done', re: /(hecho(s)?|finalizad[oa]s?|completad[oa]s?|cerrad[oa]s?|terminad[oa]s?|done)/i,
    labels: ['Done','Hecho','Finalizado','Completado','Cerrado','Terminado'] },
  { key: 'cancelled', re: /(cancelad[oa]s?|anulad[oa]s?)/i,
    labels: ['Cancelled','Cancelado','Anulado'] },
];

let listar_por_etapa = false;
let filtro_etapa = null;
if (/\bproyectos?\b/i.test(rawMsg)) {
  for (const s of stages) {
    if (s.re.test(rawMsg)) { listar_por_etapa = true; filtro_etapa = { key: s.key, labels: s.labels }; break; }
  }
}

// --- extracción de posible nombre de proyecto (para el flujo “uno solo”) ---
let proyecto = base.proyecto || '';
if (!proyecto) {
  let m = rawMsg.match(/["'“”‘’]([^"'“”‘’]+)["'“”‘’]/); if (m) proyecto = m[1];
}
if (!proyecto) {
  let m = rawMsg.match(/(?:proyecto|del\s+proyecto|estado\s+del\s+proyecto)\s+([\p{L}\d _-]+)/iu);
  if (m) proyecto = m[1].trim();
}
