  normalizadoNode.mensaje_usuario_original ||
  normalizadoNode.mensaje_original ||
  normalizadoNode.parte_en_memoria?.transcripcion_original ||
  '';

const chatId = x.chat_id ?? normalizadoNode.chat_id;

// Cliente con fallbacks
const clienteRaw =
  x.cliente_buscado ??
  x.cliente ??
  normalizadoNode.cliente ??
  normalizadoNode.parte_en_memoria?.cliente ??
  '';

const clienteBuscado = normalizar(clienteRaw);

// Parte (lo que viene del primer mensaje)
const horasParte = x.horas_parte ?? normalizadoNode.horas ?? 0;
const descripcionParte = x.descripcion_parte ?? normalizadoNode.descripcion ?? '';
const productosParte = x.productos_parte ?? normalizadoNode.productos ?? [];

console.log('🔍 VALIDAR TAREA - Cliente raw:', clienteRaw);
console.log('🔍 VALIDAR TAREA - Cliente buscado:', clienteBuscado);
console.log('🧾 Flags parte:', { isDiagnosis, ticketType, horasPresup });

// Obtener tareas del resultado HTTP (tus datos vienen como x.result)
const httpResult = x.result || x.body?.result || x.json?.result || x.data?.result || [];
const tareas = Array.isArray(httpResult) ? httpResult : [];

console.log('📋 Tareas encontradas (sin filtrar):', tareas.length);

// Obtener Km y tiempo de desplazamiento
const travelDistanceKm =
  x.travel_distance_km ??
  normalizadoNode.travel_distance_km ??
  normalizadoNode.parte_en_memoria?.travel_distance_km ??
  0;

const travelTimeHours =
  x.travel_time_hours ??
  normalizadoNode.travel_time_hours ??
  normalizadoNode.parte_en_memoria?.travel_time_hours ??
  0;


// ✅ Construir datos_parte COMPLETO (esto es lo que debe sobrevivir al flujo)
const datosParteCompleto = {
  horas: Number(horasParte) || 0,
  descripcion: String(descripcionParte || ''),
  productos: Array.isArray(productosParte) ? productosParte : [],

  // ✅ CLAVE para diagnóstico/presupuesto
  is_diagnosis_task: !!isDiagnosis,
  ticket_type: ticketType,
  horas_presupuestadas: Number(horasPresup) || 0,

  travel_distance_km: Number(travelDistanceKm) || 0,
  travel_time_hours: Number(travelTimeHours) || 0,

  // ✅ auditoría / trazabilidad
  transcripcion_original: transcripcionOriginal,
  mensaje_usuario_original: transcripcionOriginal,
};

if (tareas.length === 0) {
  return [{
    json: {
      accion: 'error_sin_tareas',
      mensaje: '❌ No hay tareas en tu calendario para hoy.',
      tareas_encontradas: 0,
      chat_id: chatId,
      cliente_buscado: clienteBuscado,

      // ✅ IMPORTANTE: devolverlo completo
      datos_parte: datosParteCompleto,
    }
  }];
}

// 1) Intentar filtrar por cliente (si tengo cliente)
let tareasFiltradas = tareas;

if (clienteBuscado) {
  tareasFiltradas = tareas.filter((t) => {
    const name = normalizar(t.name || '');
    const desc = String(t.description || '');
    const clienteEnDesc = normalizar(extraerClienteDeDescripcion(desc));

    // Match fuerte: cliente extraído del HTML
    if (
      clienteEnDesc &&
      (clienteEnDesc === clienteBuscado ||
        clienteEnDesc.includes(clienteBuscado) ||
        clienteBuscado.includes(clienteEnDesc))
    ) {
      return true;
    }

    // Fallback: buscar el texto del cliente en name/desc
    return name.includes(clienteBuscado) || normalizar(desc).includes(clienteBuscado);
  });
}

console.log('✅ Tareas tras filtro por cliente:', tareasFiltradas.length);

// Si NO hay coincidencia por cliente, NO damos error: mostramos todas para elegir
const tareasParaMostrar = (clienteBuscado && tareasFiltradas.length === 0) ? tareas : tareasFiltradas;

// Detalles de tareas (con productos limpios y cliente extraído)
const tareasConDetalles = tareasParaMostrar.map((t) => {
  const desc = String(t.description || '');
  return {
    id: t.id,
    nombre_completo: t.name,
    proyecto_id: t.project_id ? t.project_id[0] : null,
    proyecto_nombre: t.project_id ? t.project_id[1] : '',
    cliente_en_tarea: extraerClienteDeDescripcion(desc) || '',
    productos: extraerProductosDeDescripcion(desc),
  };
});

// Guardar en memoria global (si la usas todavía)
const contextoKey = `memoria_${chatId}`;
let memoria = global[contextoKey] || {};
memoria.tareas_calendario_hoy = tareasConDetalles;
memoria.cliente_buscado = clienteBuscado;
memoria.parte_en_registro = datosParteCompleto;
global[contextoKey] = memoria;

// =============================
// RESPUESTA
// =============================
let respuesta;

if (tareasConDetalles.length === 1) {
  const tarea = tareasConDetalles[0];

  const notaCliente = (clienteBuscado && tareasFiltradas.length === 0)
    ? `\nTienes 1 tarea hoy.`
    : '';

  respuesta = {
    accion: 'tarea_unica',
    tarea_id: tarea.id,
    tarea_nombre: tarea.nombre_completo,
    proyecto_id: tarea.proyecto_id,
    proyecto_nombre: tarea.proyecto_nombre,
    productos_tarea: tarea.productos,
    mensaje: [
      `✅ Encontré UNA tarea para hoy.${notaCliente}`,
      `📌 ${tarea.nombre_completo}`,
      `🏢 ${tarea.proyecto_nombre}`,
      tarea.cliente_en_tarea ? `👤 Cliente: ${tarea.cliente_en_tarea}` : '',
      `📦 ${tarea.productos}`,
      '',
      '¿Registro el parte aquí?'
    ].filter(Boolean).join('\n'),
    tareas_encontradas: 1
  };

} else {
  const notaCliente = (clienteBuscado && tareasFiltradas.length === 0)
    ? `\nTe muestro todas las tareas de hoy para que elijas:`
    : '';

  const lista = tareasConDetalles.map((t, i) =>
    `\n${i + 1}️⃣ ${t.nombre_completo}\n   🏢 ${t.proyecto_nombre}` +
    (t.cliente_en_tarea ? `\n   👤 Cliente: ${t.cliente_en_tarea}` : '') +
    `\n   📦 ${t.productos}`
  ).join('');

  respuesta = {
    accion: 'elegir_tarea_multiple',
    tareas_opciones: tareasConDetalles,
    mensaje: `🔀 Tareas para hoy:${notaCliente}${lista}\n\n✍️ Responde con el número (1, 2, 3...)`,
    tareas_encontradas: tareasConDetalles.length
  };
}

return [{
  json: {
    ...respuesta,
    chat_id: chatId,
    cliente_buscado: clienteBuscado,

    // ✅ Top-level opcional (por si lo necesitas en nodos posteriores)
    transcripcion_original: transcripcionOriginal,
    mensaje_usuario_original: transcripcionOriginal,

    // ✅ CLAVE: datos_parte completo para que registrar_tarea lo reciba
    datos_parte: datosParteCompleto,

    plataforma: x.plataforma || normalizadoNode.plataforma || 'telegram',
canal_respuesta: x.plataforma || normalizadoNode.plataforma || 'telegram',
  }
}];

