// ✅ PREPARAR BÚSQUEDA PRODUCTOS FSM (RAMA: Registrar Horas Directo FSM)
// ✅ FIX: Passthrough desde Registrar Materiales reconstruye dominio (plural/singular + default_code).
//    Antes se reutilizaba payload con ['name','ilike','juntas'] y Odoo no devolvía "Junta".

const safeFirstJson = (name) => {
  try { return $items(name, 0)?.[0]?.json ?? null; } catch { return null; }
};

const regWrap = safeFirstJson('Registrar Horas Directo FSM') || {};
const reg = regWrap.registro || regWrap || {};

const httpHoras = safeFirstJson('HTTP Registrar Horas Directo FSM') || {};
let timesheet_line_id =
  httpHoras.result ??
  httpHoras.body?.result ??
  httpHoras.json?.result ??
  null;

if (Array.isArray(timesheet_line_id)) timesheet_line_id = timesheet_line_id[0];
timesheet_line_id = Number(timesheet_line_id);

const memRow = safeFirstJson('Preparar Datos AI Agent') || {};

const chat_id =
  memRow.chat_id ??
  memRow.user_id ??
  $json.chat_id ??
  reg.chat_id ??
  null;

const db = $json.db || reg.db || memRow.db || 'mchecaazor-webinar3-main-30740598';
const uid = Number($json.uid || reg.uid || memRow.uid || 2);
const PASS = 'admin';

const STOP = new Set(['con','de','y','para','en','la','el','los','las','por','del','a','al']);

const normalize = (s) =>
  (s || '')
    .toString()
    .normalize('NFD').replace(/[\u0300-\u036f]/g,'')
    .toLowerCase()
    .replace(/[^a-z0-9%\.\ ]+/g,' ')
    .replace(/\s+/g,' ')
    .trim();

function variants(tok) {
  const out = new Set();
  if (!tok) return [];
  out.add(tok);
  if (tok.endsWith('es') && tok.length > 3) out.add(tok.slice(0, -2));
  if (tok.endsWith('s') && tok.length > 2) out.add(tok.slice(0, -1));
  if (tok.length >= 5 && (tok.endsWith('as') || tok.endsWith('os'))) out.add(tok.slice(0, -2));
  if (tok.length >= 4) {
    out.add(tok.slice(0, 4));
    if (tok.length >= 5) out.add(tok.slice(0, 5));
  }
  return [...out];
}

function tokens(nombre) {
  const base = normalize(nombre);
  if (!base) return [];
  const raw = base.split(' ').filter(t => t && !STOP.has(t));
  const uniq = new Set();
  for (const tk of raw) for (const v of variants(tk)) uniq.add(v);
  return [...uniq];
}

function buildPayloadBuscarProductos(productos_solicitados, db0, uid0, pass0) {
  let leaves = [];
  for (const p of productos_solicitados) {
    for (const tk of tokens(p.nombre)) {
      if (tk.length < 2) continue;
      leaves.push(['name', 'ilike', tk]);
      leaves.push(['default_code', 'ilike', tk]);
    }
  }
  const seen = new Set();
  leaves = leaves.filter(l => {
    const k = JSON.stringify(l);
    if (seen.has(k)) return false;
    seen.add(k);
    return true;
  });
  let domain;
  if (leaves.length === 0) {
    domain = [['id', '=', -1]];
  } else {
    const orTokens = (leaves.length === 1)
      ? [leaves[0]]
      : [...Array(leaves.length - 1).fill('|'), ...leaves];
    domain = [
      ['active', '=', true],
      ['type', 'in', ['product','consu']],
      ...orTokens
    ];
  }
  return {
    jsonrpc: '2.0',
    method: 'call',
    params: {
      service: 'object',
      method: 'execute_kw',
      args: [
        db0,
        uid0,
        pass0,
        'product.product',
        'search_read',
        [domain],
        { fields: ['id','name','uom_id','default_code'], limit: 300 }
      ]
    },
    id: Math.floor(Math.random() * 1e6),
  };
}

// 1) Desde Registrar Materiales: reconstruir SIEMPRE (no usar solo ilike del nombre plural)
if ($json.necesita_resolver_productos === true && Array.isArray($json.productos_sin_id) && $json.productos_sin_id.length > 0) {
  const productos_solicitados = $json.productos_sin_id
    .map(p => ({
      nombre: String(p?.nombre || '').trim(),
      cantidad: Number(p?.cantidad || 1),
    }))
    .filter(p => p.nombre)
    .map(p => ({ nombre: p.nombre, cantidad: Number.isFinite(p.cantidad) && p.cantidad > 0 ? p.cantidad : 1 }));

  if (productos_solicitados.length === 0) {
    return {
      necesita_resolver_productos: false,
      motivo: 'Todos los productos ya tienen product_id o no hay productos',
      productos_solicitados: [],
      ...reg,
      timesheet_line_id,
      db,
      uid,
      chat_id,
    };
  }

  const payload_buscar_productos = buildPayloadBuscarProductos(productos_solicitados, db, uid, PASS);

  return {
    necesita_resolver_productos: true,
    motivo: $json.motivo || 'Desde Registrar Materiales (búsqueda enriquecida)',
    productos_solicitados,
    payload_buscar_productos,
    timesheet_line_id,
    db,
    uid,
    ...reg,
    chat_id,
  };
}

// 2) Rama normal
const productosRaw = Array.isArray(reg.productos) ? reg.productos : [];
const productos_solicitados = productosRaw
  .map(p => ({
    nombre: (p.nombre || p.product_name || '').toString().trim(),
    cantidad: Number(p.cantidad || p.quantity || 1),
    product_id: p.product_id,
  }))
  .filter(p => p.nombre && (!p.product_id || p.product_id === false || Number(p.product_id) <= 0))
  .map(p => ({ nombre: p.nombre, cantidad: Number.isFinite(p.cantidad) && p.cantidad > 0 ? p.cantidad : 1 }));

if (productos_solicitados.length === 0) {
  return {
    necesita_resolver_productos: false,
    motivo: 'Todos los productos ya tienen product_id o no hay productos',
    productos_solicitados: [],
    ...reg,
    timesheet_line_id,
    db,
    uid,
    chat_id,
  };
}

const payload_buscar_productos = buildPayloadBuscarProductos(productos_solicitados, db, uid, PASS);

return {
  necesita_resolver_productos: true,
  payload_buscar_productos,
  productos_solicitados,
  timesheet_line_id,
  db,
  uid,
  ...reg,
  chat_id,
};

// VALIDAR PRODUCTOS (rama: Buscar Productos -> Validar Productos1)

// 1) Pool de productos encontrados (respuesta JSON-RPC del HTTP Buscar Productos)
const httpResult =
  $json.result ??
  $json.body?.result ??
  $json.json?.result ??
  [];

const pool = Array.isArray(httpResult) ? httpResult : [];

// 2) Leer datos del nodo "Preparar Búsqueda Productos"
const getFirstJson = (nodeName) => {
  try {
    return $items(nodeName, 0, 0)?.[0]?.json ?? {};
  } catch {
    return {};
  }
};

const datosBusqueda = getFirstJson('Preparar Búsqueda Productos');

// 👇 en tu Preparar Búsqueda Productos lo llamas "productos_solicitados"
const productosSolicitados = Array.isArray(datosBusqueda.productos_solicitados)
  ? datosBusqueda.productos_solicitados
  : [];

// Palabras vacías
const STOP = new Set(['con','de','y','para','en','la','el','los','las','por','del','a','al']);

// Normalización
const normalize = (s) => {
  let out = (s || '')
    .toString()
    .normalize('NFD').replace(/[\u0300-\u036f]/g,'')
    .toLowerCase()
    .replace(/\s+/g,' ')
    .trim();

  out = out
    .replace(/h/g, '')
    .replace(/ll/g, 'y')
    .replace(/v/g, 'b')
    .replace(/qu/g, 'k')
    .replace(/c(?=[ei])/g, 's')
    .replace(/z/g, 's')
    .replace(/ge/g, 'je')
    .replace(/gi/g, 'ji');

  return out;
};

function tokenVariants(tok) {
  const out = new Set([tok]);
  if (tok.endsWith('es')) out.add(tok.slice(0, -2));
  if (tok.endsWith('s'))  out.add(tok.slice(0, -1));

  const m = tok.match(/^(\d+(?:\.\d+)?)(kg|g|mg|l|ml|cm|mm|m|u|uds?)$/);
  if (m) { out.add(m[1]); out.add(m[2]); }

  return [...out];
}

function tokens(s) {
  const base = normalize(s);
  if (!base) return [];
  const raw = base.split(/[ \-_/]+/).filter(t => t && !STOP.has(t));
  const uniq = new Set();
  for (const tk of raw) {
    for (const v of tokenVariants(tk)) {
      if (v.length >= 2 || /^\d+(?:\.\d+)?$/.test(v)) uniq.add(v);
    }
  }
  return [...uniq];
}

function levenshtein(a, b) {
  a = normalize(a);
  b = normalize(b);
  const m = a.length, n = b.length;
  if (m === 0) return n;
  if (n === 0) return m;

  const dp = Array.from({ length: m + 1 }, () => Array(n + 1).fill(0));
  for (let i = 0; i <= m; i++) dp[i][0] = i;
  for (let j = 0; j <= n; j++) dp[0][j] = j;

  for (let i = 1; i <= m; i++) {
    for (let j = 1; j <= n; j++) {
      const cost = a[i - 1] === b[j - 1] ? 0 : 1;
      dp[i][j] = Math.min(
        dp[i - 1][j] + 1,
        dp[i][j - 1] + 1,
        dp[i - 1][j - 1] + cost
      );
    }
  }
  return dp[m][n];
}

function jaccardToken(a, b) {
  const A = new Set(tokens(a));
  const B = new Set(tokens(b));
  const inter = [...A].filter(x => B.has(x)).length; // ✅ .length
  const uni = new Set([...A, ...B]).size;
  return uni === 0 ? 0 : inter / uni;
}

function similarity(a, b) {
  const la = normalize(a), lb = normalize(b);
  if (!la || !lb) return 0;
  if (la === lb) return 1;

  const maxLen = Math.max(la.length, lb.length);
  const ld = levenshtein(la, lb);
  const levScore = 1 - (ld / Math.max(1, maxLen));
  const jac = jaccardToken(a, b);

  return (levScore * 0.7) + (jac * 0.3);
}

/** Quita plural típico (-s) para alinear juntas/junta, tornillos/tornillo */
function stripPluralLoose(s) {
  let t = normalize(s).replace(/\s+/g, ' ').trim();
  if (t.length < 4) return t;
  if (t.endsWith('s')) t = t.slice(0, -1);
  return t;
}

// Umbrales (más tolerante a plural / raíz común)
const THRESHOLD_HIGH = 0.82;
const MIN_SUGGESTION = 0.32;

// Índice rápido
const byName = new Map(pool.map(p => [normalize(p.name), p]));

const productosValidados = [];
const productosAmbiguos = [];

for (const sol of productosSolicitados) {
  const nombreSolicitado = (sol?.nombre || '').toString().trim();
  const cant = Number(sol?.cantidad || 1);

  if (!nombreSolicitado) continue;

  const qNorm = normalize(nombreSolicitado);
  const qStem = stripPluralLoose(nombreSolicitado);
  const qTokens = new Set(tokens(nombreSolicitado));

  // Match exacto por name normalizado
  if (byName.has(qNorm)) {
    const p = byName.get(qNorm);
    productosValidados.push({
      product_id: p.id,
      product_name: p.name,
      quantity: Number.isFinite(cant) && cant > 0 ? cant : 1,
      uom_id: Array.isArray(p.uom_id) ? p.uom_id[0] : p.uom_id,
      default_code: p.default_code ?? null,
    });
    continue;
  }

  // Coincidencia por raíz plural/singular (juntas ↔ junta)
  let stemHit = null;
  for (const p of pool) {
    const cn = normalize(p.name || '');
    if (!cn) continue;
    if (stripPluralLoose(cn) === qStem && qStem.length >= 3) {
      stemHit = p;
      break;
    }
  }
  if (stemHit) {
    productosValidados.push({
      product_id: stemHit.id,
      product_name: stemHit.name,
      quantity: Number.isFinite(cant) && cant > 0 ? cant : 1,
      uom_id: Array.isArray(stemHit.uom_id) ? stemHit.uom_id[0] : stemHit.uom_id,
      default_code: stemHit.default_code ?? null,
    });
    continue;
  }

  // Prefiltro + scoring
  const candidates = [];
  for (const p of pool) {
    const cName = p.name || '';
    const cNorm = normalize(cName);
    const cTokens = new Set(tokens(cName));
    const overlap = [...qTokens].some(t => cTokens.has(t));
    let score = similarity(nombreSolicitado, cName);
    const pStem = stripPluralLoose(cName);
    if (qStem.length >= 3 && pStem.length >= 3 && (qStem === pStem || cNorm.includes(qStem) || qNorm.includes(pStem))) {
      score = Math.max(score, 0.9);
    }

    if (overlap || score >= MIN_SUGGESTION) {
      candidates.push({
        id: p.id,
        name: cName,
        uom_id: Array.isArray(p.uom_id) ? p.uom_id[0] : p.uom_id,
        default_code: p.default_code ?? null,
        score
      });
    }
  }

  candidates.sort((a, b) => b.score - a.score);
  const best = candidates[0];
  const top = candidates.slice(0, 7);

  if (best && best.score >= THRESHOLD_HIGH) {
    productosValidados.push({
      product_id: best.id,
      product_name: best.name,
      quantity: Number.isFinite(cant) && cant > 0 ? cant : 1,
      uom_id: best.uom_id ?? null,
      default_code: best.default_code ?? null,
    });
  } else if (top.length > 0) {
    productosAmbiguos.push({
      solicitado: nombreSolicitado,
      cantidad: Number.isFinite(cant) && cant > 0 ? cant : 1,
      candidatos: top.map(x => ({
        id: x.id,
        name: x.name,
        score: Number(x.score.toFixed(2)),
      }))
    });
  } else {
    productosAmbiguos.push({
      solicitado: nombreSolicitado,
      cantidad: Number.isFinite(cant) && cant > 0 ? cant : 1,
      candidatos: []
    });
  }
}

