// BUSCAR EMPLEADO SIMPLIFICADO
const datos = $('Procesar Datos Gasto').item.json;

console.log('🔍 === BUSCAR EMPLEADO SIMPLIFICADO ===');
console.log('📥 Datos recibidos:', JSON.stringify(datos, null, 2));

const datosGasto = datos.datos_gasto;
const uid = datos.uid;
let empleadoNombre = datosGasto.empleado_nombre;

// Si empleado_nombre está vacío, usar odoo_user como fallback
if (!empleadoNombre || empleadoNombre.trim() === '') {
    empleadoNombre = datosGasto.odoo_user;
    console.log('ℹ️ Usando odoo_user como fallback:', empleadoNombre);
}

console.log('👤 Buscando empleado:', empleadoNombre);

// Preparar consulta para buscar empleado directamente en hr.employee
const consultaEmpleado = {
  jsonrpc: "2.0",
  method: "call",
  params: {
    service: "object",
    method: "execute_kw",
    args: [
      "mchecaazor-webinar3-main-30740598",
      uid,
      "admin",
      "hr.employee",
      "search_read",
      [[
        ["name", "ilike", empleadoNombre]
      ]],
      {
        fields: ["id", "name", "work_email", "user_id"]
      }
    ]
  },
  id: Math.floor(Math.random() * 1000000)
};

console.log('🔍 Consulta empleado:', JSON.stringify(consultaEmpleado, null, 2));

return {
  consulta_empleado: consultaEmpleado,
  datos_gasto: datosGasto,
  empleado_nombre: empleadoNombre,
  uid: uid
};

// VERIFICAR EMPLEADO SIMPLIFICADO (desambiguar por odoo_user ↔ work_email)
const empleadosEncontrados = $json.result || [];
const datos = $('Buscar Empleado Simplificado').item.json;
const datosGasto = datos.datos_gasto || {};
const empleadoNombre = (datos.empleado_nombre || '').toString().trim();
const uid = datos.uid;

const odooUser = (datosGasto.odoo_user || '').toString().trim().toLowerCase();

console.log('✅ === VERIFICAR EMPLEADO SIMPLIFICADO ===');
console.log('👥 Empleados encontrados:', empleadosEncontrados.length);
console.log('👤 Buscando por nombre:', empleadoNombre);
console.log('📧 Desambiguando por odoo_user:', odooUser || '(no provisto)');

if (empleadosEncontrados.length === 0) {
  console.log('❌ No se encontró empleado');
  return {
    empleado_encontrado: false,
    datos_gasto: datosGasto,
    empleado_nombre: empleadoNombre,
    uid: uid,
    mensaje_error: `❌ No encontré al empleado "${empleadoNombre}" en Odoo.\n\n💰 Gasto: ${datosGasto.importe}€ por ${datosGasto.descripcion}\n\n🤔 Verifica el nombre del empleado o el email (odoo_user).`
  };
}

// 1) Si tenemos odoo_user, priorizar coincidencia EXACTA con work_email
let candidato = null;
if (odooUser) {
  const exactEmailMatch = empleadosEncontrados.find(e =>
    (e.work_email || '').toString().trim().toLowerCase() === odooUser
  );
  if (exactEmailMatch) {
    candidato = exactEmailMatch;
    console.log('🎯 Coincidencia EXACTA por work_email:', exactEmailMatch.work_email, 'ID:', exactEmailMatch.id);
  }
}

// 2) Si no hay exacta, y hay varias, intentar coincidencia parcial por email
if (!candidato && odooUser && empleadosEncontrados.length > 1) {
  const [local, domain] = odooUser.split('@');
  const parcial = empleadosEncontrados.find(e => {
    const em = (e.work_email || '').toString().trim().toLowerCase();
    return (local && em.includes(local)) || (domain && em.endsWith('@' + domain));
  });
  if (parcial) {
    candidato = parcial;
    console.log('🔎 Coincidencia PARCIAL por work_email:', parcial.work_email, 'ID:', parcial.id);
  }
}

// 3) Si sigue sin candidato y hay un único resultado, tomarlo
if (!candidato && empleadosEncontrados.length === 1) {
  candidato = empleadosEncontrados[0];
  console.log('✔️ Único resultado, seleccionado:', candidato.name, 'ID:', candidato.id);
}

// 4) Si no hay odoo_user y hay múltiples, intentar match EXACTO por nombre
if (!candidato && !odooUser && empleadosEncontrados.length > 1) {
  const exactName = empleadosEncontrados.find(e =>
    (e.name || '').toString().trim().toLowerCase() === empleadoNombre.toLowerCase()
  );
  if (exactName) {
    candidato = exactName;
    console.log('🧭 Coincidencia EXACTA por nombre:', exactName.name, 'ID:', exactName.id);
  }
}

// 5) Si aún ambiguo, devolver error con opciones para que el flujo lo maneje
if (!candidato) {
  const opciones = empleadosEncontrados.map(e => {
    const email = e.work_email || 'sin email';
    return `${e.name} <${email}> [id:${e.id}]`;
  }).join('\n- ');
  const msg = `⚠️ Hay varias coincidencias para "${empleadoNombre}" y no se pudo desambiguar por email.\n` +
              (odooUser ? `Intenté casar con "${odooUser}".\n` : 'No se proporcionó odoo_user para desambiguar.\n') +
              `\nCoincidencias:\n- ${opciones}\n\n` +
              `💰 Gasto: ${datosGasto.importe}€ por ${datosGasto.descripcion}\n` +
              `👉 Indica el email exacto (odoo_user) o elige uno.`;

  console.log('❌ Ambigüedad en empleados. Requiere intervención.', opciones);
  return {
    empleado_encontrado: false,
    datos_gasto: datosGasto,
    empleado_nombre: empleadoNombre,
    uid: uid,
    mensaje_error: msg
  };
}

// ✅ Candidato elegido
console.log('✅ Empleado seleccionado:', candidato.name, 'Email:', candidato.work_email, 'ID:', candidato.id);

return {
  empleado_encontrado: true,
  empleado: candidato,
  datos_gasto: datosGasto,
  uid: uid
};

// CREAR GASTO SIMPLIFICADO — con manejo de error de empleado no encontrado
const empleadoEncontrado = $json.empleado_encontrado;
const empleado = $json.empleado;
const datosGasto = $json.datos_gasto;
const uid = $json.uid;

console.log('💰 === CREAR GASTO SIMPLIFICADO ===');

// Verificar si el empleado fue encontrado
if (!empleadoEncontrado) {
  console.log('❌ Empleado no encontrado, lanzando error para manejo del workflow');
  const mensajeError = $json.mensaje_error || 'No se pudo encontrar el empleado';

  // Crear un error personalizado que incluya el chat_id para poder enviar el mensaje
  const error = new Error(mensajeError);
  error.chatId = datosGasto.chat_id;
  error.description = JSON.stringify({
    error: true,
    chat_id: datosGasto.chat_id,
    mensaje: mensajeError,
    tipo: 'empleado_no_encontrado'
  });

  throw error;
}

console.log('👤 Empleado:', empleado.name, '(ID:', empleado.id, ')');
console.log('💵 Gasto:', datosGasto.importe, '€ -', datosGasto.descripcion);
console.log('📅 Fecha:', datosGasto.fecha);

// Crear gasto directamente en hr.expense
const consultaCrearGasto = {
  "jsonrpc": "2.0",
  "method": "call",
  "params": {
    "service": "object",
    "method": "execute_kw",
    "args": [
      "mchecaazor-webinar3-main-30740598",
      uid,
      "admin",
      "hr.expense",
      "create",
      [{
        "name": datosGasto.descripcion,
        "total_amount_currency": datosGasto.importe,
        "quantity": 1.0,
        "date": datosGasto.fecha,
        "employee_id": empleado.id,
        "payment_mode": "own_account",
        "product_id": 1  // Categoría "Gastos" por defecto - ajustar ID según tu configuración
      }]
    ]
  },
  "id": Math.floor(Math.random() * 1000000)
};

return {
  consulta_crear_gasto: consultaCrearGasto,
  empleado: empleado,
  datos_gasto: datosGasto,
  uid: uid,
  error: false
};

// ADJUNTAR IMAGEN AL GASTO - ACTIVO CON MANEJO DE ERROR
// Verificar si hubo error en los nodos anteriores
const datosCrearGasto = $('Crear Gasto Simplificado').item.json;

// Si el nodo anterior falló por empleado no encontrado
if (datosCrearGasto.error) {
  console.log('❌ === ERROR DETECTADO: Empleado no encontrado ===');
  console.log('📤 Preparando mensaje de error para Telegram');

  // Extraer el mensaje de error del objeto error
  let mensajeError = datosCrearGasto.mensaje_error || '❌ No se pudo crear el gasto.';

  // Si hay información del error en pairedItem
  if ($json.error && $json.error.message) {
    console.log('Error capturado:', $json.error.message);
    mensajeError = $json.error.message;
  }

  // Retornar datos para enviar mensaje de error por Telegram
  return {
    error_gasto: true,
    chat_id: datosCrearGasto.datos_gasto?.chat_id,
    mensaje_telegram: mensajeError,
    tipo: 'error_empleado_no_encontrado'
  };
}

const gastoId = $json.result; // ID del gasto creado
const datosGasto = datosCrearGasto.datos_gasto;
const uid = datosCrearGasto.uid;

console.log('🖼️ === ADJUNTAR IMAGEN - ACTIVO ===');
console.log('Gasto ID:', gastoId);
console.log('UID:', uid);
console.log('Tiene imagen flag:', datosGasto.tiene_imagen);

// Si no hay imagen, continuar sin ella
if (!datosGasto.tiene_imagen) {
  console.log('ℹ️ No hay imagen para adjuntar');
  return {
    gasto_id: gastoId,
    datos_gasto: datosGasto,
    imagen_adjuntada: false,
    imagen_base64: null,
    imagen_descargada: false,
    uid: uid,
    paso: 'sin_imagen',
    mensaje: 'Gasto creado sin imagen'
  };
}

console.log('📸 Preparando descarga de imagen...');
console.log('🆔 File ID:', datosGasto.imagen_file_id);

// Pasar datos para que el siguiente nodo descargue la imagen
return {
  gasto_id: gastoId,
  datos_gasto: datosGasto,
  imagen_file_id: datosGasto.imagen_file_id,
  img_data: datosGasto.img_data,
  uid: uid,
  paso: 'descargar_imagen',
  mensaje: 'Preparando descarga de imagen'
};

// CONSTRUIR URL DE DESCARGA CON FILE_PATH REAL
const datosAnteriores = $('Descargar y Adjuntar Imagen').item.json;
const getFileResponse = $('Obtener File Path Real').item.json;

// Crear objeto debug
const debugInfo = {
  paso: 'CONSTRUIR_URL_CON_FILE_PATH_REAL',
  respuesta_getfile: getFileResponse,
  tiene_result: !!getFileResponse.result,
  file_path_recibido: getFileResponse.result ? getFileResponse.result.file_path : null
};

// Obtener file_path real de la respuesta de getFile
let filePath = null;
if (getFileResponse.ok && getFileResponse.result && getFileResponse.result.file_path) {
  filePath = getFileResponse.result.file_path;
  debugInfo.file_path_extraido = filePath;
} else {
  debugInfo.error = 'No se pudo obtener file_path de la respuesta getFile';
  debugInfo.respuesta_completa = getFileResponse;
  return {
    ...datosAnteriores,
    ERROR: 'No se pudo obtener file_path real de la API de Telegram',
    DEBUG_COMPLETO: debugInfo
  };
}

// Construir URL completa de descarga
const tokenReal = '8163442849:AAFYMCxlzQ5z5ao6FT87GzIJhrUgVw1bu_s';
const downloadUrl = `https://api.telegram.org/file/bot${tokenReal}/${filePath}`;

debugInfo.url_construida = downloadUrl;
debugInfo.token_usado = 'TOKEN_REAL_CORRECTO';

const resultado = {
  ...datosAnteriores,
  file_path: filePath,
  download_url: downloadUrl,
  telegram_file_info: getFileResponse.result,
  DEBUG_VISIBLE: debugInfo
};

return resultado;

// PREPARAR ADJUNTO DIRECTO DESDE DESCARGA HTTP
// Metadatos desde el nodo que construye la URL
const datosAnteriores = $('Construir URL Descarga').item.json;
const gastoId = datosAnteriores.gasto_id;
const uid = datosAnteriores.uid || 2;

console.log('📎 === PREPARAR ADJUNTO DIRECTO ===');
console.log('Gasto ID:', gastoId);
console.log('UID:', uid);
console.log('🔗 download_url:', datosAnteriores.download_url);

// Validar que tenemos el gasto ID
if (!gastoId) {
  throw new Error('gastoId es requerido para crear el adjunto');
}

// 1) Intento normal: binario del item actual
let bin = null;
let binKeys = Object.keys($binary || {});
console.log('Binary keys (item actual):', binKeys);

if (binKeys.length) {
  bin = $binary[binKeys[0]];
}

// 2) Fallback: tomar binario explícitamente del nodo "Descargar Imagen HTTP"
if (!bin || !bin.data) {
  const httpItems = $items('Descargar Imagen HTTP', 0, 0) || [];
  if (httpItems.length && httpItems[0].binary) {
    const httpBinKeys = Object.keys(httpItems[0].binary);
    console.log('Binary keys (desde "Descargar Imagen HTTP"):', httpBinKeys);
    if (httpBinKeys.length) {
      bin = httpItems[0].binary[httpBinKeys[0]];
    }
  }
}

// Si aún no hay binario, detallar por qué
if (!bin || !bin.data) {
  console.log('❌ No hay binario disponible.');
  console.log('Resumen debug:', {
    tieneBinaryActual: !!$binary,
    keysBinaryActual: Object.keys($binary || {}),
    tieneItemsHTTP: !!$items('Descargar Imagen HTTP', 0, 0)?.length,
    jsonHTTP: $items('Descargar Imagen HTTP', 0, 0)?.[0]?.json || null,
  });
  throw new Error('No se encontraron datos binarios del archivo descargado');
}

// Convertir base64 → Buffer
const archivoBinario = Buffer.from(bin.data, 'base64');
console.log('✅ Binario cargado:', archivoBinario.length, 'bytes');

// Detectar tipo de archivo
let mimetype = bin.mimeType || 'image/jpeg';
let extension = bin.fileExtension || null;

// Deducción por firma si falta extensión
if (!extension) {
  const firstBytes = archivoBinario.slice(0, 8);
  const signature = firstBytes.toString('hex').toUpperCase();

  if (signature.startsWith('89504E47')) {
    mimetype = 'image/png';
    extension = 'png';
  } else if (signature.startsWith('FFD8FF')) {
    mimetype = 'image/jpeg';
    extension = 'jpg';
  } else if (signature.startsWith('47494638')) {
    mimetype = 'image/gif';
    extension = 'gif';
  } else if (signature.startsWith('52494646')) {
    mimetype = 'image/webp';
    extension = 'webp';
  } else {
    if (mimetype.includes('png')) extension = 'png';
    else if (mimetype.includes('webp')) extension = 'webp';
    else if (mimetype.includes('gif')) extension = 'gif';
    else extension = 'jpg';
  }
}

console.log('🖼️ Tipo detectado:', mimetype, 'Extensión:', extension);

// Convertir a base64 para Odoo
const archivoBase64 = archivoBinario.toString('base64');
console.log('✅ Convertido a base64:', archivoBase64.length, 'caracteres');

// Crear nombre de archivo
const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
const nombreArchivo = `Recibo-${timestamp}.${extension}`;

// Preparar consulta para Odoo
const consultaAdjunto = {
  jsonrpc: "2.0",
  method: "call",
  params: {
    service: "object",
    method: "execute_kw",
    args: [
      "mchecaazor-webinar3-main-30740598",
      uid,
      "admin",
      "ir.attachment",
      "create",
      [{
        name: nombreArchivo,
        datas: archivoBase64,
        res_model: 'hr.expense',
        res_id: gastoId,
        mimetype: mimetype,
        type: 'binary'
      }]
    ]
  },
  id: Math.floor(Math.random() * 1000000)
};

console.log('🎯 Adjunto preparado para Odoo');
console.log('📄 Nombre:', nombreArchivo);
console.log('📏 Tamaño:', archivoBinario.length, 'bytes');

return {
  gasto_id: gastoId,
  datos_gasto: datosAnteriores.datos_gasto,
  consulta_adjunto: consultaAdjunto,
  imagen_adjuntada: true,
  archivo_info: {
    nombre: nombreArchivo,
    mimetype: mimetype,
    tamaño: archivoBinario.length
  }
};

// FINALIZAR ADJUNTO DE RECIBO
const adjuntoId = $json.result;
const datosAnteriores = $('Preparar Adjunto Directo').item.json;

console.log('✅ === ADJUNTO COMPLETADO ===');
console.log('🆔 Adjunto ID:', adjuntoId);

return {
  gasto_id: datosAnteriores.gasto_id,
  datos_gasto: datosAnteriores.datos_gasto,
  imagen_adjuntada: true,
  adjunto_id: adjuntoId,
  mensaje: 'Gasto creado con recibo adjuntado exitosamente'
};

// Construir mensaje de fichaje en formato Odoo
const datosFichaje = $('Procesar Respuesta').item.json;
const datosUsuario = $json; // fila de BD

const odooUser = datosUsuario.odoo_user || null;
