const longitude = datosFichaje.longitude;

let mensajeOdoo = '';
if (latitude && longitude && odooUser) {
  mensajeOdoo = `Fichar ubicacion: ${latitude}, ${longitude}\nEmpleado: ${odooUser}`;
} else {
  mensajeOdoo = datosFichaje.mensaje_usuario || 'Fichar ubicacion';
}

console.log('📍 Mensaje de fichaje para Odoo:', mensajeOdoo);

return {
  ...datosFichaje,
  ...datosUsuario,
  odoo_user: odooUser,
  tiene_odoo_user: !!(odooUser && String(odooUser).trim() !== ''),
  mensaje_fichaje: mensajeOdoo,
  latitude: latitude,
  longitude: longitude
