let odooUserId = null;

try {
  const authBody = { jsonrpc: '2.0', method: 'call', params: { service: 'common', method: 'authenticate', args: [db, 'admin', pass, {}] }, id: 1 };
  const authRes = await this.helpers.httpRequest({ method: 'POST', url, body: authBody, json: true });
  const uid = authRes?.result;
  if (!uid) throw new Error('No UID');

  // 1) Resolver res.users por login/email de Supabase
  if (odooLogin) {
    const userBody = {
      jsonrpc: '2.0',
      method: 'call',
      params: {
        service: 'object',
        method: 'execute_kw',
        args: [db, uid, pass, 'res.users', 'search_read', [['|', ['login', '=', odooLogin], ['email', '=', odooLogin]]], { fields: ['id', 'login', 'email'], limit: 1 }]
      },
      id: 2
    };

    const userRes = await this.helpers.httpRequest({ method: 'POST', url, body: userBody, json: true });
    const users = userRes?.result || [];
    if (users.length && users[0]?.id) {
      odooUserId = Number(users[0].id);
    }
  }

  // 2) Fallback opcional con id numérico si aplica
  if (!odooUserId && ultimo.user_id != null) {
    const candidate = Number(typeof ultimo.user_id === 'object' ? ultimo.user_id?.[0] : ultimo.user_id);
    if (Number.isFinite(candidate) && candidate > 0 && candidate < 1000000) {
      odooUserId = candidate;
    }
  }

  // 3) Buscar última línea de horas por user directo o user del empleado
  if (odooUserId) {
    const searchBody = {
      jsonrpc: '2.0',
      method: 'call',
      params: {
        service: 'object',
        method: 'execute_kw',
        args: [
          db,
          uid,
          pass,
          'account.analytic.line',
          'search_read',
          [['|', ['user_id', '=', odooUserId], ['employee_id.user_id', '=', odooUserId]]],
          { fields: ['id', 'create_date'], order: 'create_date desc', limit: 1 }
        ]
      },
      id: 3
    };

    const searchRes = await this.helpers.httpRequest({ method: 'POST', url, body: searchBody, json: true });
    const rows = searchRes?.result || [];
    if (rows.length && rows[0]?.id) {
      horasId = Number(rows[0].id);
    }
  }

  // 4) Último fallback por login/email relacionado
  if ((!horasId || horasId <= 0) && odooLogin) {
    const searchByLoginBody = {
      jsonrpc: '2.0',
      method: 'call',
      params: {
        service: 'object',
        method: 'execute_kw',
        args: [
          db,
          uid,
          pass,
          'account.analytic.line',
          'search_read',
