// ✅ PREPARAR ADJUNTO DIRECTO (PARTE) - compatible Telegram/WhatsApp

const safeItems = (nodeName) => {
  try {
    return $items(nodeName, 0, 0) || [];
  } catch (e) {
    return [];
  }
};

const firstJson = (nodeName) => {
  const arr = safeItems(nodeName);
  return arr.length ? (arr[0].json || {}) : {};
};

const datosBase =
  firstJson('Construir URL Descarga Parte1') ||
  firstJson('Extraer Datos') ||
  {};

const ultimo = firstJson('Consultar Último Parte Odoo1');
const horasId = Number(ultimo.ultimo_horas_id);

